INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2800,85,0,2041,'sét');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2801,76,0,2041,'<p>Bút gel siêu trơn Deli E6600S là giải pháp tuyệt vời cho những ai tìm kiếm sự êm ái tối đa trong từng nét chữ. Nhờ công nghệ mực đặc biệt giúp giảm ma sát, cây bút lướt nhẹ nhàng trên giấy tựa như không, mang lại cảm giác thoải mái và thư giãn. Bên cạnh đó, thiết kế tay cầm có khả năng chống trơn trượt hiệu quả, giúp bạn cầm bút chắc chắn và thoải mái ngay cả khi phải sử dụng liên tục trong thời gian dài.</p>\r\n<p> </p>\r\n<ul>\r\n<li>Mã sản phẩm: E6600S</li>\r\n<li>Loại sản phẩm: Bút bi mực gel siêu trơn.</li>\r\n<li>Kích thước ngòi: 0.5mm.</li>\r\n<li>Màu mực: Xanh dương.</li>\r\n<li>Quy cách: Thiết kế hiện đại, cầm chắc tay.</li>\r\n</ul>\r\n<ul>\r\n<li>Công nghệ mực “siêu mượt”: Mực bút chứa thành phần bôi trơn đặc biệt bao phủ các hạt màu, giúp giảm thiểu đáng kể ma sát giữa đầu bút và mặt giấy.</li>\r\n<li>Trải nghiệm viết trơn tru: Bạn không cần ấn mạnh tay mà mực vẫn ra đều, đậm và liên tục, khắc phục hoàn toàn tình trạng rít hay gai ngòi thường gặp.</li>\r\n<li>Nét bút tinh tế: Đầu bi 0.5mm cho ra nét chữ thanh mảnh, gọn gàng, giúp trang viết sạch đẹp và dễ nhìn.</li>\r\n<li>Thiết kế nắp đậy bảo vệ ngòi tối ưu: Giúp bảo quản ngòi bút tốt hơn, tránh hư hỏng hoặc khô mực khi không sử dụng.</li>\r\n<li>Thân bút trong suốt dễ quan sát: Cho phép bạn kiểm soát lượng mực còn lại một cách dễ dàng và chủ động.</li>\r\n<li>Thay ngòi tiện lợi, tiết kiệm: Khi dùng hết mực, bạn có thể thay ngòi mới nhanh chóng, giúp tăng thời gian sử dụng và tiết kiệm chi phí hiệu quả.<br><br>\r\n<p>Sản phẩm đặc biệt phù hợp với:</p>\r\n<ul>\r\n<li>Học sinh, sinh viên cần tốc độ viết nhanh để chép bài.</li>\r\n<li>Người làm văn phòng thường xuyên ghi chú, ký văn bản.</li>\r\n<li>Bất kỳ ai muốn hạn chế tình trạng mỏi tay khi viết nhiều.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong>CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li>Cách sử dụng: Viết trực tiếp lên giấy, mực xuống đều ngay khi chạm bút. Đậy nắp (hoặc thu ngòi) ngay sau khi dùng xong để mực luôn tươi mới.</li>\r\n<li>Bảo quản: Bảo quản ở nhiệt độ thường, tránh ánh nắng gắt. Tránh làm rơi bút ở tư thế cắm đầu xuống đất để bảo vệ đầu bi.<br><br><br><br></li>\r\n</ul>\r\n</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2802,76,0,2042,'<p>1. MÔ TẢ SẢN PHẨM<br>Bộ bút màu Acrylic Marker Deli HM166 là “chìa khóa” mở ra cánh cửa sáng tạo không giới hạn cho bất kỳ ai yêu thích hội họa và đồ thủ công (DIY). Không chỉ đơn thuần là vẽ trên giấy, với bộ bút này, bạn có thể tự tay “trang điểm” cho đôi giày cũ, chiếc ốp lưng điện thoại nhàm chán hay những viên sỏi vô tri trở nên rực rỡ sắc màu. Với bảng màu “khủng” lên đến 60 màu, sản phẩm đáp ứng từ nhu cầu tập vẽ cơ bản đến các tác phẩm nghệ thuật chuyên nghiệp.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: HM166<br>Loại sản phẩm: Bút sơn Acrylic / Acrylic Marker.<br>Phân loại bộ màu:<br>HM166-12: Hộp 12 màu.<br>HM166-24: Hộp 24 màu.<br>HM166-36: Hộp 36 màu.<br>HM166-48: Hộp 48 màu.<br>HM166-60: Hộp 60 màu.<br>Mực: Mực gốc nước (Water-based), độ che phủ cao.<br>Đơn vị tính: Hộp/Bộ.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Vẽ trên mọi bề mặt: Đây là “siêu năng lực” của bút Acrylic HM166. Bạn có thể thoải mái sáng tạo trên vải (quần áo, giày canvas, túi tote), gốm sứ (cốc, bát), thủy tinh, nhựa, gỗ, đá và dĩ nhiên là cả giấy.<br>Độ che phủ tuyệt đối: Mực Acrylic có khả năng che phủ cực tốt. Bạn có thể dễ dàng tô màu sáng đè lên nền màu tối hoặc sửa lỗi sai bằng cách đợi lớp màu cũ khô và tô màu mới lên trên mà không sợ bị lem hay xỉn màu.<br>Màu sắc tươi sáng, bền bỉ: Hệ màu phong phú, chuẩn sắc và rực rỡ. Sau khi mực khô hoàn toàn, tranh vẽ có khả năng kháng nước tốt, không bị phai màu nhanh dưới ánh sáng, giúp tác phẩm của bạn bền đẹp theo thời gian.<br>An toàn và Tiện lợi: Mực không có mùi hắc khó chịu như sơn dầu, an toàn cho sức khỏe. Thiết kế thân bút vừa tay, ngòi bút linh hoạt giúp đi nét hoặc tô mảng đều dễ dàng.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là lựa chọn hoàn hảo cho:<br>Học sinh, Sinh viên: Vẽ trang trí báo tường, sổ tay, làm bài tập mỹ thuật.<br>Tín đồ DIY/Handmade: “Custom” giày dép, vẽ áo, trang trí đồ dùng cá nhân.<br>Người yêu hội họa: Cần bộ màu đa năng, tiện lợi để phác thảo ý tưởng mọi lúc mọi nơi.<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Lắc đều bút trước khi sử dụng để mực và dung môi hòa tan đều (đặc biệt quan trọng với màu Acrylic).<br>Với bút mới, ấn nhẹ ngòi bút xuống mặt giấy vài lần để kích hoạt mực chảy xuống.<br>Vẽ trực tiếp lên bề mặt vật liệu.<br>Đợi lớp màu khô hẳn nếu muốn vẽ chồng lớp tiếp theo.<br>Bảo quản:<br>Quan trọng: Đóng chặt nắp ngay sau khi dùng (nghe tiếng “tách”) để tránh mực bị khô tắc ở đầu ngòi.<br>Nên đặt bút nằm ngang khi bảo quản để mực phân bố đều, giúp bút bền hơn và mực ra đều hơn ở lần sử dụng sau.<br>Tránh để nơi có nhiệt độ quá cao hoặc ánh nắng trực tiếp gay gắt.</p>');
