INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2804,76,0,2043,'<ol>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">MÔ TẢ SẢN PHẨM</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Bút gel siêu trơn Deli E6600S là giải pháp tuyệt vời cho những ai tìm kiếm sự êm ái tối đa trong từng nét chữ. Nhờ công nghệ mực đặc biệt giúp giảm ma sát, cây bút lướt nhẹ nhàng trên giấy tựa như không, mang lại cảm giác thoải mái và thư giãn. Bên cạnh đó, thiết kế tay cầm có khả năng chống trơn trượt hiệu quả, giúp bạn cầm bút chắc chắn và thoải mái ngay cả khi phải sử dụng liên tục trong thời gian dài.</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">THÔNG SỐ KỸ THUẬT</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Mã sản phẩm: E6600S</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Loại sản phẩm: Bút bi mực gel siêu trơn.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Kích thước ngòi: 0.5mm.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Màu mực: Xanh dương.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Quy cách: Thiết kế hiện đại, cầm chắc tay.</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">ĐẶC ĐIỂM SẢN PHẨM</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Công nghệ mực “siêu mượt”: Mực bút chứa thành phần bôi trơn đặc biệt bao phủ các hạt màu, giúp giảm thiểu đáng kể ma sát giữa đầu bút và mặt giấy.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Trải nghiệm viết trơn tru: Bạn không cần ấn mạnh tay mà mực vẫn ra đều, đậm và liên tục, khắc phục hoàn toàn tình trạng rít hay gai ngòi thường gặp.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Nét bút tinh tế: Đầu bi 0.5mm cho ra nét chữ thanh mảnh, gọn gàng, giúp trang viết sạch đẹp và dễ nhìn.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Thiết kế nắp đậy bảo vệ ngòi tối ưu: Giúp bảo quản ngòi bút tốt hơn, tránh hư hỏng hoặc khô mực khi không sử dụng.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Thân bút trong suốt dễ quan sát: Cho phép bạn kiểm soát lượng mực còn lại một cách dễ dàng và chủ động.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Thay ngòi tiện lợi, tiết kiệm: Khi dùng hết mực, bạn có thể thay ngòi mới nhanh chóng, giúp tăng thời gian sử dụng và tiết kiệm chi phí hiệu quả.</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\">\r\n<p><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Sản phẩm đặc biệt phù hợp với:</span></p>\r\n<p><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Học sinh, sinh viên cần tốc độ viết nhanh để chép bài.</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Người làm văn phòng thường xuyên ghi chú, ký văn bản.</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Bất kỳ ai muốn hạn chế tình trạng mỏi tay khi viết nhiều.</span></p>\r\n</li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">CÁCH SỬ DỤNG VÀ BẢO QUẢN</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Cách sử dụng: Viết trực tiếp lên giấy, mực xuống đều ngay khi chạm bút. Đậy nắp (hoặc thu ngòi) ngay sau khi dùng xong để mực luôn tươi mới.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Bảo quản: Bảo quản ở nhiệt độ thường, tránh ánh nắng gắt. Tránh làm rơi bút ở tư thế cắm đầu xuống đất để bảo vệ đầu bi.</span></li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2805,85,0,2043,'Bút Gel siêu trơn Deli E6600S');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2806,76,0,2044,'<ol>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\"> MÔ TẢ SẢN PHẨM</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Băng dính Deli EA689 là vật dụng “nhỏ nhưng có võ”, luôn hiện diện trên bàn làm việc của dân văn phòng hay trong hộp bút của các bạn học sinh. Với kích thước tiêu chuẩn 18mm cùng độ dài 30 yards, sản phẩm đáp ứng hoàn hảo các nhu cầu dán dính cơ bản hàng ngày. Đặc biệt, đóng gói theo bộ 8 cuộn giúp bạn tiết kiệm chi phí và luôn có sẵn đồ dự trữ khi cần thiết.</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">THÔNG SỐ KỸ THUẬT</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Mã sản phẩm: EA689</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Loại sản phẩm: Băng dính văn phòng (Adhesive Tape).</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Kích thước: Rộng 18mm x Dài 30 yards (tương đương khoảng 27 mét).</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Độ dày màng: 38µm (microns) – Độ dày tiêu chuẩn, khó đứt.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Quy cách đóng gói: 8 cuộn/lốc.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Màu sắc: Màu lẫn (Nhiều màu sắc sinh động).</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">ĐẶC ĐIỂM SẢN PHẨM</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Kích thước “vàng” cho văn phòng: Khổ rộng 18mm là kích thước phổ biến nhất, vừa vặn để dán các mép giấy, niêm phong phong bì thư hay gói các hộp quà nhỏ mà không bị quá to hay quá nhỏ.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Màng dai, khó đứt: Với độ dày 38µm, băng dính có độ dai tốt, chịu được lực kéo căng vừa phải khi thao tác mà không bị đứt ngang chừng, giúp công việc của bạn không bị gián đoạn.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Độ bám dính cao: Lớp keo chất lượng giúp băng dính bám chắc trên nhiều bề mặt như giấy, bìa carton, nhựa… Mối dán bền đẹp, không bị bong tróc theo thời gian.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Màu sắc đa dạng: Bộ sản phẩm gồm nhiều màu sắc khác nhau (hoặc lõi màu), giúp bạn dễ dàng phân loại tài liệu hoặc dùng để trang trí, tạo điểm nhấn cho các gói quà.</span></li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\">\r\n<p><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\"> ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Sản phẩm là vật tư tiêu hao thiết yếu cho:</span></p>\r\n<p><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Học sinh, Sinh viên: Bọc bìa sách vở, làm thủ công, dán ghi chú.</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Nhân viên văn phòng: Dán tài liệu, niêm phong thư từ.</span><br><span style=\"font-family: arial, helvetica, sans-serif; font-size: 16px;\">Cửa hàng tạp hóa/Online: Gói hàng hóa nhỏ.</span></p>\r\n</li>\r\n<li style=\"font-family: arial, helvetica, sans-serif;\"><span style=\"font-family: arial, helvetica, sans-serif;\">CÁCH SỬ DỤNG VÀ BẢO QUẢN</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Cách sử dụng:</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Có thể dùng kéo cắt thủ công hoặc lắp vào các dụng cụ cắt băng dính để bàn (cối cắt băng dính) để thao tác nhanh và đường cắt đẹp hơn.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Dán lên bề mặt khô ráo, sạch bụi để keo bám tốt nhất.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Bảo quản:</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Quan trọng: Tránh để cuộn băng dính ở nơi có nhiệt độ quá cao hoặc ánh nắng trực tiếp, vì nhiệt độ sẽ làm chảy keo và biến dạng màng nhựa.</span><br><span style=\"font-family: arial, helvetica, sans-serif;\">Để nơi sạch sẽ, tránh bụi bám vào hai bên cạnh cuộn băng dính làm giảm độ dính.</span></li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2807,85,0,2044,'Băng dính Deli EA689');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2808,76,0,2045,'<p>1. MÔ TẢ SẢN PHẨM<br>Vở học sinh Deli CNB200 là giải pháp “lưu trữ kiến thức” tối ưu dành cho các môn học có lượng kiến thức lớn. Với độ dày lên đến 200 trang, cuốn vở này giúp các bạn học sinh ghi chép liên tục, liền mạch suốt cả kỳ học mà không cần phải thay vở mới giữa chừng. Đây là sự lựa chọn hoàn hảo cho những môn học chính như Toán, Văn, hoặc dùng để tổng hợp kiến thức ôn thi.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: CNB200<br>Loại sản phẩm: Vở học sinh.<br>Số trang: 200 trang (Độ dày lớn).<br>Quy cách đóng gáy: Gáy ghim.<br>Các phiên bản bìa (Mã đuôi):<br>CNB200-STR: Chủ đề họa tiết sọc, đường phố hoặc ngôi sao cá tính.<br>CNB200-HLD: Chủ đề kỳ nghỉ, phong cảnh thư giãn.<br>CNB200-SPO: Chủ đề thể thao năng động, mạnh mẽ.<br>Đơn vị tính: Quyển.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Số trang “khủng” 200 trang: Đây là ưu điểm lớn nhất của sản phẩm. Cuốn vở dày dặn đáp ứng nhu cầu ghi chép nhiều, hạn chế việc phải dùng nhiều cuốn vở mỏng cho một môn học, giúp việc ôn tập và tra cứu lại kiến thức cũ trở nên dễ dàng, hệ thống hơn.<br>Giấy viết chất lượng cao: Bề mặt giấy láng mịn, viết êm tay và ăn mực. Giấy có độ dày và độ chắn sáng tốt, giúp hạn chế tình trạng mực bị thấm hay hằn sang mặt sau, ngay cả khi sử dụng bút máy hay bút dạ quang.<br>Gáy ghim bền bỉ: Dù có độ dày lớn, vở vẫn được gia cố bằng ghim thép chắc chắn, giữ cho các trang giấy không bị bung rời hay xô lệch trong quá trình lật giở thường xuyên.<br>Thiết kế bìa đa dạng: Bộ sản phẩm có nhiều mẫu bìa bắt mắt, từ phong cách thể thao khỏe khoắn (SPO) đến các họa tiết trẻ trung (STR) hay hình ảnh nhẹ nhàng (HLD), phù hợp với sở thích đa dạng của cả nam và nữ sinh.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm đặc biệt phù hợp cho:<br>Học sinh cấp 2, cấp 3: Dùng cho các môn học chính, khối lượng kiến thức nhiều (Toán, Văn, Lý, Hóa, Sử…).<br>Sinh viên: Ghi chép bài giảng trên giảng đường (thường viết rất nhiều và nhanh).<br>Người đi làm: Dùng làm sổ tay ghi chép công việc, nhật ký hàng ngày trong thời gian dài.</p>\r\n<p>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Mở vở và viết lên các dòng kẻ in sẵn.<br>Do vở dày, khi viết đến các trang giữa có thể cần vuốt nhẹ nếp gáy để trang giấy nằm phẳng hơn.<br>Nên bọc bìa nilon bên ngoài để bảo vệ bìa vở luôn mới và tránh rách góc.<br>Bảo quản:<br>Để nơi khô ráo, thoáng mát. Tránh nơi ẩm ướt dễ làm giấy bị mốc hoặc phồng rộp.<br>Tránh làm rơi vở từ trên cao xuống để không làm hỏng góc gáy.<br>Không bẻ ngược bìa vở quá mạnh tay.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2809,85,0,2045,'Vở học sinh 200 trang Deli CNB200');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2810,76,0,2046,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Máy tính để bàn Deli E1239 (Màu bạc) là trợ thủ đắc lực cho những ai làm việc với các con số mỗi ngày. Sở hữu vẻ ngoài sang trọng với lớp vỏ màu bạc kim loại cùng màn hình lớn dễ nhìn, sản phẩm không chỉ giúp công việc tính toán, kế toán trở nên nhanh chóng, chính xác mà còn tạo điểm nhấn chuyên nghiệp và đẳng cấp cho bàn làm việc của </li>\r\n<li> THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: E1239<br>Loại sản phẩm: Máy tính để bàn (Desktop Calculator).<br>Màu sắc: Bạc (Silver).<br>Màn hình hiển thị: 12 số (12 digits).<br>Nguồn năng lượng: 2 nguồn (Pin tiểu + Năng lượng ánh sáng).<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Màn hình lớn, hiển thị rõ nét: Máy được thiết kế với màn hình LCD to, hiển thị rõ ràng 12 chữ số. Đặc biệt, màn hình có độ nghiêng vừa phải giúp bạn dễ dàng quan sát kết quả ở mọi góc độ mà không bị lóa hay mỏi mắt khi làm việc dưới ánh đèn văn phòng.<br>Bàn phím to, nảy và êm: Các phím bấm được thiết kế to, khoảng cách rộng rãi và có độ đàn hồi tốt. Điều này giúp bạn thao tác nhập liệu nhanh “như gió” mà vẫn đảm bảo độ chính xác cao, hạn chế tối đa việc bấm nhầm phím.<br>Mặt kim loại bền bỉ: Lớp vỏ mặt trước thường được ốp tấm kim loại màu bạc, không chỉ tăng tính thẩm mỹ, sang trọng mà còn giúp máy chịu được va đập tốt hơn, bền bỉ theo thời gian.<br>Năng lượng kép (Dual Power): Máy sử dụng linh hoạt giữa pin và năng lượng ánh sáng (mặt trời/đèn điện). Khi ở môi trường đủ sáng, máy sẽ tự động dùng năng lượng ánh sáng để tiết kiệm pin, giúp bạn yên tâm sử dụng trong thời gian dài mà không lo hết pin đột ngột.</li>\r\n<li>\r\n<p><span style=\"font-size: 16px;\">ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-size: 16px;\">Sản phẩm là vật dụng không thể thiếu cho:</span></p>\r\n<p><span style=\"font-size: 16px;\">Kế toán, Tài chính: Cần tính toán số liệu chính xác, liên tục.</span><br><span style=\"font-size: 16px;\">Chủ cửa hàng, Thu ngân: Tính tiền hàng nhanh chóng cho khách.</span><br><span style=\"font-size: 16px;\">Nhân viên văn phòng: Thực hiện các phép tính thông dụng hàng ngày.</span></p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Nhấn nút “AC” hoặc “ON” để bắt đầu.<br>Sử dụng các phím số và phím chức năng (+, -, x, ÷, %, M+, M-…) để thực hiện phép tính.<br>Máy thường có chế độ tự động tắt sau một khoảng thời gian không sử dụng để tiết kiệm pin.<br>Bảo quản:<br>Tránh để nước hoặc chất lỏng đổ vào bàn phím.<br>Không để máy rơi rớt mạnh gây hỏng màn hình LCD.<br>Nếu màn hình hiển thị mờ khi ở nơi thiếu sáng, hãy thay pin mới.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2811,85,0,2046,'Máy tính để bàn Deli E1239');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2812,76,0,2047,'<ol>\r\n<li> MÔ TẢ SẢN PHẨM<br>Tẩy chì Deli EH301 là phụ kiện học tập nhỏ xinh không thể thiếu trong hộp bút của các bạn học sinh. Với thiết kế đơn giản nhưng hiệu quả cùng nhiều màu sắc tươi tắn, sản phẩm giúp bạn dễ dàng “hô biến” những vết chì sai sót, giữ cho trang vở luôn sạch đẹp và tinh tươm.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EH301<br>Loại sản phẩm: Gôm tẩy chì (Eraser).<br>Màu sắc: Màu lẫn (Nhiều màu sắc trong một hộp).<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Tẩy sạch êm ái: Chất tẩy có độ mềm vừa phải, bám giấy tốt, giúp lấy đi các hạt than chì (HB, 2B) một cách nhẹ nhàng. Bạn không cần dùng quá nhiều lực mà vết bẩn vẫn biến mất nhanh chóng.<br>Bảo vệ giấy: Nhờ kết cấu dẻo dai, tẩy hạn chế tối đa ma sát gây mòn hay rách giấy. Đây là điểm cộng lớn khi sử dụng trên các loại giấy vở mỏng hoặc giấy thi trắc nghiệm.<br>Màu sắc vui tươi: Sản phẩm có nhiều phiên bản màu sắc khác nhau, mang lại cảm giác trẻ trung, năng động và giúp bạn dễ dàng tìm thấy cục tẩy trong đống sách vở.<br>Ít bụi (Se bụi): Khi tẩy, các vụn tẩy sẽ kết dính lại thành sợi thay vì nát vụn ra bàn, giúp bạn dễ dàng thu dọn vệ sinh và giữ góc học tập gọn gàng.</li>\r\n<li>\r\n<p><span style=\"font-size: 16px;\"> ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-size: 16px;\">Sản phẩm là vật dụng thiết yếu cho:</span></p>\r\n<p><span style=\"font-size: 16px;\">Học sinh, Sinh viên: Sử dụng hàng ngày trong học tập và thi cử.</span><br><span style=\"font-size: 16px;\">Nhân viên văn phòng: Dùng để tẩy xóa các ghi chú chì.</span><br><span style=\"font-size: 16px;\">Người dùng phổ thông: Cần một chiếc tẩy nhỏ gọn, hiệu quả và giá thành hợp lý.</span></p>\r\n</li>\r\n<li><span style=\"font-size: 16px;\">CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Cầm chắc tẩy và chà nhẹ lên vùng cần xóa.<br>Bảo quản: Nên giữ lại lớp vỏ giấy bọc ngoài (nếu có) để cầm tẩy sạch tay hơn. Bảo quản nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp và nhiệt độ cao làm cứng tẩy.</span></li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2813,85,0,2047,'Tẩy chì Deli EH301');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2814,76,0,2048,'<p>1. MÔ TẢ SẢN PHẨM<br>Túi đựng bút Deli EH914 là phụ kiện học tập mang phong cách trẻ trung, tối giản với dòng chữ “Good Tasty” hoặc họa tiết nhẹ nhàng điểm xuyết. Được may từ chất liệu vải Canvas dày dặn, sản phẩm không chỉ bền bỉ mà còn mang lại cảm giác mộc mạc, gần gũi. Với kích thước nhỏ gọn nhưng lòng túi rộng rãi, đây là “kho chứa” lý tưởng cho hàng tá bút viết và dụng cụ học tập, giúp góc học tập của bạn luôn gọn gàng và ngăn nắp.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EH914<br>Loại sản phẩm: Túi đựng bút / Hộp bút vải.<br>Kích thước: Khoảng 190 x 50 x 50 mm (Dài x Rộng x Cao).<br>Chất liệu: Vải Canvas (Vải bố) cao cấp.<br>Màu sắc: Màu lẫn (Xanh dương, Hồng, Be, Xanh lá…) – Giao màu ngẫu nhiên.<br>Đơn vị tính: Chiếc.<br>3. ĐẶC ĐIỂM SẢN PHẨM<br>Chất liệu Canvas bền đẹp: Vải Canvas có đặc tính sợi vải to, dệt chắc chắn, giúp túi giữ form tốt, ít bị sờn rách và dễ dàng vệ sinh khi bị bẩn. Chất vải này cũng mang lại vẻ ngoài “vintage” và thời trang hơn so với các loại hộp nhựa.<br>Sức chứa ấn tượng: Dù nhìn bên ngoài khá gọn gàng, nhưng nhờ thiết kế hình hộp chữ nhật thuôn dài, túi có thể chứa được số lượng lớn bút bi, thước kẻ (loại 15-18cm), gôm tẩy và các vật dụng nhỏ khác.<br>Khóa kéo trơn tru: Khóa kéo được gia công tỉ mỉ, kéo mượt mà, không bị kẹt vải. Tay cầm khóa kéo thường được làm to bản hoặc có dây giúp bạn dễ dàng thao tác đóng mở.<br>Màu sắc Pastel trang nhã: Sản phẩm thường có các tông màu pastel dịu mắt, phù hợp với nhiều lứa tuổi và sở thích, tạo cảm giác thư giãn khi nhìn vào.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm rất được ưa chuộng bởi:<br>Học sinh, Sinh viên: Đựng dụng cụ học tập hàng ngày đi học.<br>Nhân viên văn phòng: Đựng bút viết, mỹ phẩm nhỏ gọn hoặc phụ kiện điện thoại (cáp sạc, tai nghe) khi đi làm.<br>Người yêu thích sự tối giản: Thích các sản phẩm vải mộc mạc, ít chi tiết cầu kỳ.<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Kéo khóa mở túi.<br>Sắp xếp bút viết và dụng cụ vào bên trong.<br>Kéo khóa lại để bảo quản.<br>Bảo quản:<br>Vệ sinh: Có thể giặt tay nhẹ nhàng với xà phòng loãng nếu túi bị bẩn, sau đó phơi khô ở nơi thoáng mát.<br>Tránh dùng bàn chải cứng chà mạnh lên bề mặt vải làm xù lông.<br>Tránh để mực bút bi dây trực tiếp ra lòng túi (nên đậy nắp bút kỹ trước khi cất).</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2815,85,0,2048,'Túi đựng bút Deli EH914');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2816,76,0,2049,'<p>1. MÔ TẢ SẢN PHẨM<br>Dập ghim Deli E0414 là “trợ thủ đắc lực” cho công việc văn phòng và học tập cần xử lý lượng giấy tờ vừa phải. Với thiết kế công thái học ôm tay và khả năng bấm “ngọt” lên đến 25 tờ giấy cùng lúc, sản phẩm giúp bạn đóng gáy báo cáo, tài liệu một cách chắc chắn, nhanh chóng mà không tốn nhiều sức lực.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: E0414<br>Loại sản phẩm: Dập ghim trung.<br>Công suất bấm: Khoảng 25 tờ giấy (định lượng tiêu chuẩn 70gsm).<br>Loại ghim sử dụng: Ghim số 24/6 hoặc 26/6 (Loại ghim chân lớn phổ biến).<br>Chất liệu: Lõi thép không gỉ, vỏ bọc nhựa ABS cao cấp.<br>Màu sắc: Đa dạng (Xanh dương, Xám, Đen…) – Giao màu ngẫu nhiên.<br>Đơn vị tính: Chiếc.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Công suất mạnh mẽ: Khác với các dòng dập ghim mini (số 10) chỉ bấm được mỏng, Deli E0414 sử dụng ghim lớn hơn (24/6 hoặc 26/6), cho phép xuyên thủng và cố định chắc chắn tập tài liệu dày tới 25 tờ một cách dễ dàng.<br>Lò xo đàn hồi tốt: Cơ chế lò xo linh hoạt giúp lực bấm nhẹ, dứt khoát. Bạn không cần phải gồng tay ấn mạnh, hạn chế mỏi tay khi phải đóng hồ sơ liên tục.<br>Thiết kế chống trượt: Đế dập ghim thường được lót lớp đệm hoặc thiết kế nhám giúp sản phẩm bám chắc trên mặt bàn, không bị trượt đi khi bạn thao tác.<br>Chế độ bấm linh hoạt: Mâm đe (phần kim loại đỡ ghim ở đế) thường có thể xoay được để chuyển đổi giữa hai chế độ: bấm ghim cụp vào trong (để lưu trữ lâu dài) hoặc bẻ ghim ra ngoài (để tháo ghim dễ dàng khi cần – tùy thiết kế chi tiết từng lô hàng).</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp cho nhu cầu sử dụng tần suất trung bình đến cao:<br>Nhân viên văn phòng: Đóng hợp đồng, báo cáo, hồ sơ dày.<br>Giáo viên: Kẹp bài kiểm tra, giáo án.<br>Học sinh, Sinh viên: Đóng tiểu luận, tài liệu ôn tập.<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Kéo nắp trên của dập ghim lên.<br>Nạp thanh ghim (loại 24/6 hoặc 26/6) vào rãnh chứa.<br>Đóng nắp lại cho khớp.<br>Đưa tập giấy vào khe và ấn tay dứt khoát.<br>Bảo quản:<br>Để nơi khô ráo, tránh ẩm ướt gây gỉ sét lò xo.<br>Tránh làm rơi mạnh từ trên cao làm lệch trục bấm.<br>Để xa tầm tay trẻ em (do ghim lớn và nhọn).</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2817,85,0,2049,'Dập ghim 25 trang Deli E0414');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2818,76,0,2050,'<p>1. MÔ TẢ SẢN PHẨM<br>Pin Carbon Deli EL203 (Pin tiểu AA) là giải pháp năng lượng tiết kiệm và hiệu quả cho các thiết bị điện tử thông dụng hàng ngày. Với công nghệ sản xuất hiện đại, pin đảm bảo dòng điện ổn định, an toàn và thân thiện với môi trường nhờ loại bỏ các kim loại nặng độc hại. Quy cách đóng gói túi 4 viên tiện lợi giúp bạn dễ dàng thay thế đồng loạt cho các thiết bị như đồng hồ, điều khiển, đồ chơi.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EL203<br>Loại sản phẩm: Pin Carbon (Pin than / Zinc-Carbon).<br>Kích thước: AA (Pin tiểu / Pin số 5).<br>Điện áp: 1.5V.<br>Màu sắc: Màu đen.<br>Quy cách đóng gói: 4 viên/túi.<br>3. ĐẶC ĐIỂM SẢN PHẨM<br>An toàn và Thân thiện: Sản phẩm được sản xuất theo tiêu chuẩn “xanh”, không chứa Thủy ngân (Mercury) và Cadmium, đảm bảo an toàn cho sức khỏe người dùng và giảm thiểu ô nhiễm môi trường khi thải bỏ.<br>Hiệu suất ổn định: Cung cấp dòng điện 1.5V ổn định, phù hợp nhất cho các thiết bị tiêu thụ điện năng thấp đến trung bình, giúp thiết bị hoạt động trơn tru và kéo dài tuổi thọ.<br>Vỏ pin chất lượng: Vỏ pin được gia công chắc chắn, có khả năng chịu lực tốt và chống rò rỉ dung dịch điện phân, bảo vệ các linh kiện bên trong thiết bị của bạn khỏi bị ăn mòn.<br>Tiết kiệm chi phí: Là dòng pin Carbon (Pin than), sản phẩm có giá thành rất hợp lý, là lựa chọn kinh tế cho nhu cầu sử dụng thường xuyên trong gia đình và văn phòng.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng thiết yếu cho mọi nhà và văn phòng, chuyên dùng cho:<br>Thiết bị gia dụng: Đồng hồ treo tường, điều khiển tivi, điều khiển điều hòa.<br>Đồ chơi trẻ em: Các loại xe mô hình, đèn đồ chơi công suất nhỏ.<br>Thiết bị văn phòng: Chuột máy tính (loại thường), đèn pin nhỏ.<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Lắp pin đúng chiều cực Dương (+) và cực Âm (-) theo hướng dẫn trên thiết bị.<br>Nên thay toàn bộ pin mới cùng lúc, không lắp chung pin cũ và pin mới để đảm bảo hiệu suất.<br>Bảo quản:<br>Để nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp.<br>Tháo pin ra khỏi thiết bị nếu không sử dụng trong thời gian dài để tránh pin bị chảy nước làm hỏng lò xo tiếp xúc.<br>Để xa tầm tay trẻ em.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2819,85,0,2050,'Pin tiểu con thỏ Deli EL203');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2820,76,0,2051,'<p>1. MÔ TẢ SẢN PHẨM<br>Bộ đất nặn Deli EH712 là món quà tuyệt vời giúp bé “thổi hồn” vào những ý tưởng ngộ nghĩnh. Với chất liệu mềm dẻo và bảng màu tươi sáng, sản phẩm mang đến cho bé không gian sáng tạo vô hạn, từ việc nặn những con vật đáng yêu đến các loại hoa quả đầy màu sắc. Tùy vào nhu cầu, ba mẹ có thể chọn cho bé hộp 8 màu cơ bản hoặc hộp 12 màu phong phú hơn để bé thỏa sức vui chơi.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EH712<br>Phân loại:<br>EH712-8: Hộp 8 màu.<br>EH712-12: Hộp 12 màu.<br>Loại sản phẩm: Đất nặn thủ công (Modeling Clay).<br>Đơn vị tính: Hộp.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Mềm mịn, dễ nhào nặn: Đất có độ dẻo và mềm mại, rất dễ thao tác ngay cả với những đôi tay nhỏ bé của trẻ mầm non. Bé có thể dễ dàng uốn nắn, tạo hình chi tiết mà không cần dùng quá nhiều lực.<br>Không dính tay, sạch sẽ: Sản phẩm được chế tạo đặc biệt để không gây bết dính vào tay hay quần áo, giúp bé vui chơi thoải mái mà vẫn giữ vệ sinh sạch sẽ, ba mẹ cũng đỡ vất vả hơn khi dọn dẹp.<br>Màu sắc tươi tắn: Các thỏi màu có độ bão hòa cao, rực rỡ và bắt mắt. Bé có thể trộn các màu lại với nhau theo tỉ lệ để tạo ra những gam màu mới lạ, kích thích tư duy nghệ thuật và khả năng nhận biết màu sắc.<br>An toàn cho bé: Được làm từ nguyên liệu an toàn, không chứa chất độc hại, có mùi hương nhẹ dễ chịu, đảm bảo sức khỏe cho trẻ khi tiếp xúc trực tiếp.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp cho:</p>\r\n<p>Trẻ em (từ 3 tuổi trở lên): Vui chơi giải trí, phát triển kỹ năng vận động tinh tại nhà.<br>Trường mầm non: Sử dụng trong các tiết học thủ công, tạo hình.<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Rửa tay sạch và lau khô trước khi chơi.<br>Lấy đất ra khỏi bao bì, nhào nhẹ cho đất mềm hơn.<br>Sử dụng tay hoặc dụng cụ hỗ trợ để tạo hình theo ý thích.<br>Trộn màu: Lấy hai phần đất khác màu nhào chung để tạo ra màu thứ ba (Ví dụ: Đỏ + Vàng = Cam).<br>Bảo quản:<br>Quan trọng: Sau khi chơi xong, cần gói kín đất nặn hoặc cất vào hộp đậy nắp để tránh bụi bẩn và giữ cho đất không bị khô cứng.<br>Bảo quản nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp và nơi có nhiệt độ cao.<br>Lưu ý an toàn: Sản phẩm không ăn được. Cần có sự giám sát của người lớn khi trẻ nhỏ chơi để tránh nuốt phải.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2821,85,0,2051,'Đất nặn Deli EH712');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2822,76,0,2052,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Bút bi bấm Deli EQ41 (Màu xanh) là sự lựa chọn hoàn hảo cho những ai yêu thích nét viết đậm đà và sự tiện lợi tối đa. Với ngòi bút 0.7mm trơn mượt cùng cơ chế bấm lò xo linh hoạt, sản phẩm giúp bạn ghi chép nhanh chóng, ký tên rõ ràng, mang lại hiệu quả cao trong công việc và học tập hàng ngày.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EQ41-BL<br>Loại sản phẩm: Bút bi bấm (Ballpoint Pen).<br>Kích thước ngòi: 0.7mm (Nét trung bình/đậm).<br>Màu mực: Xanh dương.<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Ngòi 0.7mm êm ái: Kích thước ngòi 0.7mm lớn hơn các loại bút 0.5mm thông thường, giúp mực xuống nhiều và đều hơn. Điều này tạo ra nét chữ đậm, rõ ràng, rất thích hợp để ký tên hoặc viết các tiêu đề nổi bật.<br>Cơ chế bấm tiện lợi: Thiết kế dạng bấm lò xo giúp bạn sử dụng nhanh chóng chỉ bằng một ngón tay, loại bỏ hoàn toàn nỗi lo làm rơi hay mất nắp bút.<br>Mực dầu khô nhanh: Bút sử dụng mực dầu chất lượng, khô ngay khi chạm giấy, không bị lem nhem khi viết tốc ký hay vô tình quẹt tay qua.<br>Cầm nắm chắc chắn: Thân bút được thiết kế vừa vặn, thường có đệm cao su hoặc vân chống trượt ở phần tay cầm, giúp bạn viết lâu mà không bị mỏi hay trơn trượt do mồ hôi.</li>\r\n<li>\r\n<p><span style=\"font-size: 16px;\">ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-size: 16px;\">Sản phẩm rất được ưa chuộng bởi:</span></p>\r\n<p><span style=\"font-size: 16px;\">Nhân viên văn phòng: Dùng để ký kết văn bản, ghi chú nhanh trong cuộc họp.</span><br><span style=\"font-size: 16px;\">Học sinh, Sinh viên: Dùng để viết bài, đặc biệt là các bạn thích nét chữ to, rõ.</span><br><span style=\"font-size: 16px;\">Giáo viên: Dùng để chấm bài hoặc ghi lời phê.</span></p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Bấm đuôi bút để ngòi lộ ra và viết. Bấm lại lần nữa để thu ngòi về sau khi sử dụng. Gỡ bỏ hạt sáp bảo vệ ở đầu ngòi (đối với bút mới).<br>Bảo quản: Luôn thu ngòi bút về khi không sử dụng để tránh khô mực đầu bi và bảo vệ ngòi nếu lỡ làm rơi. Bảo quản nơi khô ráo, tránh nhiệt độ quá cao.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2823,85,0,2052,'Bút bi bấm Deli EQ41-BL');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2824,76,0,2053,'<ol>\r\n<li>\r\n<p><span style=\"font-size: 16px;\"> MÔ TẢ SẢN PHẨM</span><br><span style=\"font-size: 16px;\">Bút máy Deli CQ890 là giải pháp “ăn chắc mặc bền” được rất nhiều phụ huynh tin chọn cho con em mình. Điểm đặc biệt nhất của bộ sản phẩm này là sự chu đáo từ nhà sản xuất: tặng kèm ngay một ngòi bút thay thế. Điều này giúp các bạn học sinh yên tâm luyện chữ, nếu lỡ tay làm rơi hỏng ngòi thì có thể thay thế ngay lập tức để tiếp tục bài học mà không cần mua bút mới.</span></p>\r\n<p> </p>\r\n</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: CQ890<br>Loại sản phẩm: Bút máy học sinh.<br>Quy cách đóng gói: 01 Bút + 01 Ngòi thay thế / Hộp.<br>Đơn vị tính: Hộp.<br>Đối tượng: Học sinh tiểu học.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Tặng kèm ngòi dự phòng: Đây là ưu điểm kinh tế vượt trội. Trẻ nhỏ thường hiếu động và hay làm rơi bút khiến ngòi bị toè hoặc gãy. Với chiếc ngòi thứ 2 đi kèm sẵn trong hộp, ba mẹ tiết kiệm được chi phí và thời gian đi mua sắm lại.<br>Ngòi bút trơn mượt: Ngòi bút được gia công kỹ lưỡng, cho mực xuống đều, nét viết trơn tru, liền mạch. Bé viết nhẹ nhàng, không cần ấn mạnh gây rách giấy hay mỏi tay.<br>Thiết kế vừa tay: Thân bút có kích thước phù hợp với bàn tay nhỏ của học sinh tiểu học, giúp bé cầm nắm chắc chắn và điều khiển nét bút dễ dàng.<br>Dễ dàng bơm mực: Hệ thống bơm mực (piston) hoạt động trơn tru, dễ thao tác, giúp việc nạp mực trở nên nhanh chóng và sạch sẽ.</li>\r\n<li>\r\n<p>ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là lựa chọn “vàng” cho:</p>\r\n<p>Học sinh Tiểu học: Đặc biệt là các bé mới tập viết, hay làm rơi bút.<br>Phụ huynh: Muốn tìm mua loại bút tiết kiệm, sử dụng được lâu dài.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Bơm mực vào thân bút và viết như bình thường.<br>Cách thay ngòi: Dùng khăn giấy hoặc vải mềm rút nhẹ ngòi cũ ra và lắp ngòi dự phòng vào đúng khớp.<br>Bảo quản:<br>Quan trọng: Đậy nắp ngay sau khi không sử dụng để tránh mực bị khô tắc ở đầu ngòi.<br>Rửa sạch bút bằng nước ấm nếu để lâu không dùng hoặc khi muốn đổi màu mực.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2825,85,0,2053,'Bút máy Deli CQ890');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2826,76,0,2054,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Bút highlight Deli EU366 (dòng Umbo) là trợ thủ đắc lực giúp bạn làm nổi bật những thông tin quan trọng một cách nhanh chóng và hiệu quả. Với thiết kế hiện đại, màu sắc mực tươi sáng cùng công nghệ mực an toàn, EU366 không chỉ giúp trang sách, tài liệu của bạn trở nên khoa học, dễ nhìn mà còn mang lại cảm hứng học tập và làm việc đầy hứng khởi.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EU366<br>Loại sản phẩm: Bút nhớ dòng (Highlight).<br>Kiểu ngòi: Ngòi vát (Chisel tip).<br>Nét viết: Linh hoạt từ 1mm đến 5mm.<br>Màu mực: Vàng, Cam, Hồng, Xanh lá.<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Ngòi vát đa năng: Thiết kế đầu ngòi vát xéo giúp bạn dễ dàng thay đổi nét bút. Bạn có thể dùng cạnh nhỏ để gạch chân (1mm) hoặc dùng bề mặt rộng để tô đậm cả dòng chữ (5mm) một cách trơn tru.<br>Mực tươi sáng, khô nhanh: Mực bút có độ bão hòa màu cao, tươi tắn nhưng không gây chói mắt. Đặc biệt, mực khô ngay sau khi viết (Dry Fast), giúp trang giấy sạch sẽ, không bị lem nhem khi bạn vô tình chạm tay vào.<br>An toàn và dễ chịu: Sản phẩm sử dụng dòng mực ít mùi (Low Smell), không chứa chất độc hại, đảm bảo an toàn tuyệt đối cho sức khỏe người dùng, kể cả trẻ em.<br>Thiết kế trẻ trung: Thân bút cầm vừa tay, màu vỏ bút trùng với màu mực giúp bạn dễ dàng nhận biết và lựa chọn.</li>\r\n<li>\r\n<p><span style=\"font-size: 16px;\">ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-size: 16px;\">Sản phẩm là vật dụng không thể thiếu đối với:</span></p>\r\n<p><span style=\"font-size: 16px;\">Học sinh, sinh viên: Dùng để đánh dấu kiến thức trọng tâm, ôn thi hiệu quả.</span><br><span style=\"font-size: 16px;\">Nhân viên văn phòng: Giúp phân loại thông tin, highlight các ý chính trong văn bản, báo cáo.</span><br><span style=\"font-size: 16px;\">Người yêu thích đọc sách: Đánh dấu những câu trích dẫn hay mà không làm hỏng giấy.</span></p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Mở nắp và tô trực tiếp lên phần văn bản cần đánh dấu. Nên thử bút ra giấy nháp trước nếu bút mới mua để mực xuống đều.<br>Bảo quản: Đậy chặt nắp ngay sau khi sử dụng để tránh làm khô mực (tiếng “tách” báo hiệu nắp đã đóng kín). Bảo quản nơi khô ráo, tránh ánh nắng trực tiếp và nhiệt độ cao.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2827,85,0,2054,'Bút highlight Deli EU366 ');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2828,76,0,2055,'<p>1. MÔ TẢ SẢN PHẨM<br>Bộ màu nước Deli Emotion EC22 mang đến thế giới cảm xúc đầy màu sắc cho các tác phẩm hội họa của bạn. Với thiết kế dạng tuýp tiện dụng và dung tích 15ml “hào phóng”, sản phẩm là lựa chọn kinh tế và chất lượng để các bạn học sinh, sinh viên hay những người mới bắt đầu làm quen với nghệ thuật vẽ màu nước thỏa sức sáng tạo nên những bức tranh trong trẻo và bay bổng.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EC22<br>Dòng sản phẩm: Emotion Series.<br>Loại sản phẩm: Màu nước dạng tuýp.<br>Dung tích: 15ml/tuýp.<br>Phân loại bộ màu:<br>EC22-6: Hộp 6 màu.<br>EC22-8: Hộp 8 màu.<br>EC22-12: Hộp 12 màu.<br>Đơn vị tính: Hộp.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Màu sắc trong trẻo, tươi sáng: Đặc trưng của màu nước là độ trong và khả năng loang màu tự nhiên. Màu Deli EC22 lên giấy rất tươi, sắc nét và có độ trong trẻo cao, giúp bức tranh có chiều sâu và sự mềm mại đặc trưng.<br>Dễ dàng pha trộn: Bạn có thể hòa tan màu với nước để điều chỉnh các sắc độ đậm nhạt khác nhau, hoặc trộn các màu gốc lại với nhau để tạo ra vô vàn tông màu mới lạ. Chất màu mịn, tan nhanh trong nước và không bị lợn cợn.<br>Dạng tuýp tiện lợi: Thiết kế tuýp nhựa mềm giúp bạn dễ dàng kiểm soát lượng màu lấy ra, tránh lãng phí. Nắp vặn chắc chắn giúp bảo quản màu bên trong không bị khô hay đổ ra ngoài khi di chuyển.<br>Dung tích lớn 15ml: So với các loại tuýp nhỏ thông thường (chỉ khoảng 5-10ml), dung tích 15ml giúp bạn sử dụng được lâu hơn, thoải mái tô vẽ các mảng lớn mà không lo nhanh hết màu.<br>An toàn: Sản phẩm được làm từ nguyên liệu an toàn, không chứa chất độc hại, thân thiện với người sử dụng.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp cho:<br>Học sinh, Sinh viên: Dùng cho môn mỹ thuật, vẽ tranh phong cảnh, tĩnh vật tại trường.<br>Người mới học vẽ màu nước: Cần bộ màu cơ bản, dễ sử dụng và giá thành hợp lý để luyện tập các kỹ thuật loang màu (wet-on-wet), chồng màu.</p>\r\n<p>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Bóp một lượng màu nhỏ bằng hạt đậu ra khay pha màu (palette).<br>Nhúng cọ vào nước sạch, sau đó hòa vào màu để đạt độ loãng mong muốn.<br>Vẽ lên giấy chuyên dụng cho màu nước (giấy có định lượng dày, thường từ 200gsm trở lên) để màu loang đẹp và không làm cong giấy.<br>Bảo quản:<br>Quan trọng: Đóng chặt nắp tuýp ngay sau khi lấy màu để tránh không khí làm khô màu bên trong.<br>Rửa sạch cọ và khay pha màu ngay sau khi sử dụng.<br>Bảo quản nơi khô ráo, thoáng mát.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2829,85,0,2055,'Màu nước Emotion Deli EC22');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2830,76,0,2056,'<p>1. MÔ TẢ SẢN PHẨM<br>Bút sáp màu dạng vặn Deli EC217 là cuộc cách mạng “sạch sẽ” trong hộp bút của bé. Với thiết kế thông minh hoạt động như một thỏi son, bé không cần phải gọt, không cần bóc giấy và đặc biệt là không bao giờ lo sáp dây bẩn ra tay. Phiên bản thân dài giúp lượng sáp nhiều hơn, cầm nắm thoải mái hơn, cho bé thỏa sức tô vẽ những bức tranh rực rỡ sắc màu một cách tiện lợi và tiết kiệm nhất.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EC217<br>Loại sản phẩm: Bút sáp màu dạng vặn (Twistable Crayon).<br>Phân loại bộ màu:<br>EC217-12: Hộp 12 màu.<br>EC217-18: Hộp 18 màu.<br>EC217-24: Hộp 24 màu.<br>Thiết kế: Thân dài, vỏ nhựa bảo vệ.<br>Đơn vị tính: Hộp/Vỉ.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Cơ chế vặn xoay thông minh: Điểm sáng giá nhất của sản phẩm là cơ chế “vặn đến đâu, dùng đến đó”. Khi đầu sáp mòn, bé chỉ cần xoay nhẹ đuôi bút là ngòi sáp sẽ được đẩy lên tiếp tục sử dụng. Thiết kế này giúp loại bỏ hoàn toàn phiền toái khi phải gọt bút hay bóc lớp giấy bọc như sáp thường.<br>Giữ tay luôn sạch sẽ: Toàn bộ lõi sáp được bao bọc bởi lớp vỏ nhựa cứng cáp. Tay bé không bao giờ phải chạm trực tiếp vào sáp, đảm bảo sạch sẽ tuyệt đối, không dính màu vào quần áo hay bàn ghế.<br>Thân dài, lõi bền: Lớp vỏ nhựa đóng vai trò như “áo giáp” bảo vệ lõi sáp bên trong không bị gãy khi bé lỡ tay làm rơi hoặc tì mạnh. Thiết kế thân dài chứa lượng sáp nhiều hơn, giúp bé sử dụng được lâu hơn.<br>Màu sắc tươi sáng: Chất sáp mềm, màu lên chuẩn và tươi tắn. Bé tô nhẹ nhàng là màu đã phủ đều mặt giấy.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là lựa chọn số 1 cho:<br>Các bé sợ bẩn tay: Giúp bé thoải mái sáng tạo mà không lo lấm lem.<br>Ba mẹ muốn tiết kiệm: Hạn chế tối đa tình trạng sáp bị gãy vụn lãng phí.<br>Học sinh Tiểu học: Mang đi học rất tiện và sạch hộp bút.</p>\r\n<p>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Mở nắp bút.<br>Vặn đuôi bút theo chiều kim đồng hồ để ngòi sáp nhô lên một đoạn vừa đủ (khoảng 1cm). Lưu ý: Không vặn quá dài vì sáp dễ bị gãy khi tì lực.<br>Tô màu trực tiếp lên giấy.<br>Vặn ngược lại để thu ngòi sáp vào trong trước khi đóng nắp.<br>Bảo quản:<br>Tránh để bút ở nơi có nhiệt độ cao (gần lửa, cốp xe) vì sáp bên trong có thể bị chảy.<br>Đóng nắp sau khi dùng để bảo vệ đầu ngòi.<br>Không quăng ném mạnh làm vỡ vỏ nhựa.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2831,85,0,2056,'Bút sáp vặn thân dài Deli EC217');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2832,76,0,2057,'<p>1. MÔ TẢ SẢN PHẨM<br>Bút dạ nước thân tròn Deli EC165 là người bạn đồng hành thân thiết trong cặp sách của biết bao thế hệ học sinh. Với thiết kế thân tròn cổ điển dễ cầm nắm cùng bảng màu rực rỡ từ 12 đến 24 màu, sản phẩm giúp các bé thoải mái tô vẽ, phát huy trí tưởng tượng phong phú và rèn luyện đôi tay khéo léo qua từng nét vẽ mượt mà.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EC165<br>Loại sản phẩm: Bút dạ màu / Bút lông màu.<br>Thiết kế thân: Thân tròn.<br>Phân loại bộ màu:<br>EC165-12: Hộp 12 màu.<br>EC165-18: Hộp 18 màu.<br>EC165-24: Hộp 24 màu.<br>Đơn vị tính: Hộp/Vỉ.</p>\r\n<p><br>3. ĐẶC ĐIỂM SẢN PHẨM<br>Thân tròn dễ cầm: Thiết kế thân bút hình trụ tròn cổ điển, kích thước vừa vặn với tay cầm của trẻ nhỏ. Kiểu dáng này giúp bé dễ dàng xoay bút để điều chỉnh góc vẽ, tạo cảm giác thoải mái khi cầm lâu.<br>Mực ra đều, màu tươi sáng: Ngòi bút được làm từ sợi polyester cao cấp, giúp mực xuống đều, không bị tắc quãng hay lem nhem. Màu sắc hiển thị trên giấy rất tươi tắn, chuẩn màu, giúp bức tranh của bé thêm phần sinh động.<br>Ngòi bút bền bỉ: Đầu ngòi cứng cáp, chịu lực tốt, hạn chế tình trạng bị tòe ngòi hay thụt ngòi vào trong khi bé lỡ tay ấn mạnh xuống giấy.<br>An toàn và Dễ rửa trôi: Mực bút sử dụng hệ mực gốc nước an toàn, không có mùi hắc. Đặc biệt, mực có tính năng “Washable” (dễ rửa trôi), nếu bé lỡ dính mực vào tay hoặc quần áo, ba mẹ có thể dễ dàng làm sạch bằng nước và xà phòng.<br>Nắp thông khí an toàn: Nắp bút được thiết kế có lỗ thông khí, đảm bảo an toàn theo tiêu chuẩn châu Âu, tránh nguy cơ ngạt thở nếu trẻ vô tình nuốt phải.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp cho:<br>Trẻ mầm non &amp; Tiểu học: Dùng để tập tô màu, vẽ tranh tự do.<br>Học sinh: Sử dụng trong các giờ học Mỹ thuật, vẽ bản đồ tư duy (Mindmap).<br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Mở nắp và vẽ trực tiếp lên giấy.<br>Phù hợp để tô các mảng màu rộng hoặc đi nét viền đậm.<br>Không nên tô đi tô lại một chỗ quá nhiều lần để tránh làm rách giấy.<br>Bảo quản:<br>Quan trọng: Nhắc bé đậy chặt nắp ngay sau khi sử dụng (nghe tiếng “tách”) để ngòi bút không bị khô mực.<br>Nếu ngòi bị khô, có thể nhúng nhẹ đầu bút vào nước ấm để mực chảy lại.<br>Tránh để nơi có nhiệt độ quá cao.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2833,85,0,2057,'Bút dạ nước thân tròn Deli EC165');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2834,76,0,2058,'<p>1. MÔ TẢ SẢN PHẨM<br>Màu Acrylic Deli EC12 là “vua” của sự đa năng trong thế giới hội họa. Không chỉ gói gọn trên những trang giấy, với bộ màu này, bạn có thể biến mọi đồ vật xung quanh thành tác phẩm nghệ thuật: từ vẽ lên vải (giày, áo), gỗ, đá, cho đến gốm sứ hay kính. Với chất lượng màu bền bỉ, kháng nước và độ bám dính cực cao, đây là lựa chọn hoàn hảo cho những ai đam mê sáng tạo và muốn lưu giữ tác phẩm của mình lâu dài.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EC12<br>Loại sản phẩm: Màu Acrylic (Sơn Acrylic).<br>Dung tích: 12ml / tuýp.<br>Quy cách đóng gói:<br>EC12-12: Hộp 12 màu.<br>EC12-24: Hộp 24 màu.<br>Đơn vị tính: Hộp.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Vẽ trên mọi chất liệu: Đây là ưu điểm vượt trội nhất của màu Acrylic. Bạn có thể thỏa sức “custom” giày sneaker, vẽ trang trí túi tote, vẽ tranh trên đá cuội hay trang trí ốp lưng điện thoại. Màu bám dính tốt trên hầu hết các bề mặt thô nhám hay trơn bóng.<br>Kháng nước và Bền màu: Sau khi khô hoàn toàn, màu Acrylic sẽ tạo thành một lớp màng nhựa cứng cáp, không bị trôi khi gặp nước và rất bền màu với thời gian. Bạn có thể yên tâm giặt nhẹ nhàng các sản phẩm vải đã vẽ mà không lo phai màu.<br>Độ che phủ cao: Màu có khả năng chồng lớp tuyệt vời. Bạn dễ dàng tô màu sáng đè lên màu tối hoặc sửa lỗi sai bằng cách phủ lớp màu mới lên trên mà không sợ bị lem nhem.<br>Khô nhanh: Màu Acrylic khô rất nhanh (thường chỉ trong vài phút), giúp bạn rút ngắn thời gian hoàn thành tác phẩm mà không phải chờ đợi lâu như sơn dầu.<br>Màu sắc rực rỡ: Hệ màu đa dạng, tươi sáng. Bạn có thể pha trộn các màu với nhau hoặc pha thêm chút nước để tạo hiệu ứng như màu nước (nhưng khi khô vẫn kháng nước).</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là “người bạn thân thiết” của:<br>Học sinh, Sinh viên Mỹ thuật: Dùng cho các bài tập trang trí màu, vẽ tranh giá vẽ.<br>Tín đồ DIY/Handmade: Yêu thích việc tự tay trang trí đồ đạc, quần áo.<br>Người mới bắt đầu: Cần loại màu dễ sử dụng, dễ sửa lỗi và bền đẹp.</p>\r\n<p><br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Bóp màu ra khay (palette).<br>Có thể dùng trực tiếp hoặc pha thêm một chút nước để màu loãng hơn (Lưu ý: Không pha quá nhiều nước sẽ làm giảm độ bám dính).<br>Vẽ lên bề mặt mong muốn.<br>Đợi lớp màu khô hẳn trước khi vẽ chồng lớp khác.<br>Bảo quản (Cực kỳ quan trọng):<br>Rửa cọ ngay lập tức: Màu Acrylic khi khô sẽ cứng như nhựa và không thể rửa sạch, làm hỏng cọ vĩnh viễn. Vì vậy, hãy rửa sạch cọ và khay pha màu ngay sau khi vẽ xong.<br>Đóng chặt nắp tuýp màu sau khi sử dụng để tránh màu bị khô cứng bên trong.<br>Bảo quản nơi khô ráo, thoáng mát.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2835,85,0,2058,'Màu Acrylic Deli EC12');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2836,76,0,2059,'<ol>\r\n<li> MÔ TẢ SẢN PHẨM<br>Hồ khô Deli NS147-B sẽ đốn tim các bạn học sinh ngay từ cái nhìn đầu tiên với giao diện “Gấu Bơ” (Butter Bear) siêu đáng yêu và đang cực kỳ “hot”. Không chỉ là dụng cụ thủ công tiện ích, thỏi hồ này còn như một món phụ kiện trang trí xinh xắn, mang lại niềm vui và cảm hứng sáng tạo mỗi khi ngồi vào bàn học. Với dung tích lớn 21g, bạn có thể thoải mái sử dụng trong thời gian dài mà không lo hết giữa chừng.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: NS147-B<br>Loại sản phẩm: Hồ khô / Keo dán dạng thỏi.<br>Chủ đề thiết kế: Gấu Bơ (Butter Bear).<br>Trọng lượng: 21g (Size lớn).<br>Chất liệu keo: ACR (Acrylic) – Độ bám dính cao.<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Thiết kế Gấu Bơ “Trend”: Vỏ ngoài được in hình chú Gấu Bơ ngộ nghĩnh, màu sắc tươi sáng, bắt mắt. Đây chắc chắn là món đồ dùng học tập khiến các bé thích thú và muốn sở hữu ngay lập tức.<br>Dung tích lớn (21g): So với các loại hồ khô thông thường (chỉ khoảng 8g – 15g), thỏi hồ này có lượng keo nhiều hơn hẳn (21g). Điều này giúp tiết kiệm chi phí và thời gian mua sắm, đặc biệt phù hợp với các bạn hay làm thủ công thường xuyên.<br>Keo ACR dính chắc, khô nhanh: Chất keo Acrylic cao cấp giúp độ bám dính cực tốt trên giấy, bìa, ảnh… Keo khô nhanh, đường dán sạch sẽ, không làm nhăn hay ướt giấy như hồ nước, đảm bảo tính thẩm mỹ cho bài làm.<br>An toàn và Tiện lợi: Cơ chế vặn xoắn thông minh giúp đẩy keo lên dễ dàng. Chất liệu an toàn, không mùi độc hại, phù hợp cho học sinh sử dụng hàng ngày.</li>\r\n<li>\r\n<p><span style=\"font-size: 16px;\">ĐỐI TƯỢNG SỬ DỤNG</span><br><span style=\"font-size: 16px;\">Sản phẩm là lựa chọn yêu thích của:</span></p>\r\n<p><span style=\"font-size: 16px;\">Học sinh (Tiểu học, THCS): Đặc biệt là các bạn nữ yêu thích những món đồ văn phòng phẩm “cute”, dễ thương.</span><br><span style=\"font-size: 16px;\">Người yêu sáng tạo: Dùng để trang trí sổ tay (Bullet Journal), làm đồ handmade.</span></p>\r\n</li>\r\n<li><span style=\"font-size: 16px;\">CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Mở nắp bảo vệ hình gấu.<br>Xoay nhẹ núm vặn ở đáy để keo nhô lên một đoạn vừa đủ dùng.<br>Thoa đều keo lên mặt giấy và dán.<br>Bảo quản:<br>Quan trọng: Đậy nắp thật chặt ngay sau khi sử dụng (nghe tiếng “tách” hoặc cảm thấy chặt tay) để keo không bị khô cứng.<br>Để nơi khô ráo, tránh ánh nắng trực tiếp hoặc nơi có nhiệt độ quá cao làm chảy keo.</span></li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2837,85,0,2059,'Hồ khô Gấu Bơ Deli NS147-B');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2838,76,0,2060,'<ol>\r\n<li>\r\n<p> MÔ TẢ SẢN PHẨM<br>Hồ nước Deli E7302S là “người bạn” quen thuộc trong cặp sách của biết bao thế hệ học sinh. Với chất keo trong suốt và đầu bôi tiện lợi, sản phẩm giúp việc dán giấy thủ công hay niêm phong bao thư trở nên dễ dàng, nhanh chóng. Dung tích 50ml nhỏ gọn, vừa vặn để các bé mang đi học mỗi ngày mà không chiếm diện tích hộp bút.</p>\r\n<p> </p>\r\n</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: E7302S<br>Loại sản phẩm: Hồ nước / Keo dán lỏng (Liquid Glue).<br>Dung tích: 50ml.<br>Màu sắc keo: Trong suốt.<br>Đơn vị tính: Chai/Lọ.</li>\r\n<li> ĐẶC ĐIỂM SẢN PHẨM<br>Keo trong, dán đẹp: Chất keo lỏng trong suốt, không màu, giúp mối dán đảm bảo tính thẩm mỹ, không để lại các vệt ố vàng hay làm tối màu giấy sau khi khô.<br>Đầu bôi silicon thông minh: Đầu chai được thiết kế dạng đầu silicon mềm có lỗ nhỏ, giúp bạn dễ dàng tản đều keo ra mặt giấy chỉ bằng vài đường lướt nhẹ. Thiết kế này giúp kiểm soát lượng keo chảy ra vừa đủ, hạn chế tình trạng keo ồ ạt làm ướt nhẹp hay rách giấy mỏng.<br>An toàn và Dễ làm sạch: Sản phẩm có mùi nhẹ, không hắc, không chứa chất độc hại, an toàn cho trẻ nhỏ. Đặc biệt, vì là hồ nước nên nếu lỡ dính vào tay hay quần áo, bạn hoàn toàn có thể rửa sạch dễ dàng bằng nước thường.<br>Độ kết dính tốt: Keo khô tương đối nhanh và bám dính chắc chắn trên bề mặt giấy, bìa.</li>\r\n<li>\r\n<p>ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp cho mọi lứa tuổi:</p>\r\n<p>Học sinh: Dùng trong giờ học thủ công, cắt dán hình ảnh.<br>Nhân viên văn phòng: Dùng để dán tem, phong bì thư, tài liệu giấy.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Tháo nắp bảo vệ.<br>Nếu mới sử dụng lần đầu, có thể cần tháo bỏ nút chặn bên trong (tùy mẫu).<br>Bóp nhẹ thân chai và di chuyển đầu silicon để thoa keo lên bề mặt giấy.<br>Dán hai mặt giấy lại với nhau và vuốt nhẹ cho phẳng.<br>Bảo quản:<br>Quan trọng: Đóng nắp chặt ngay sau khi sử dụng để tránh đầu keo bị khô tắc.<br>Nên để chai ở tư thế đứng, tránh dốc ngược làm keo chảy ra nắp gây dính bẩn khi mở.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2839,85,0,2060,'Hồ nước Deli E7302S');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2840,76,0,2061,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Keo siêu dính Deli EA526 (thường gọi là Keo 502 cao cấp) là “cứu tinh” cho những món đồ gãy hỏng trong gia đình. Với đặc tính khô nhanh tức thì và khả năng kết dính cực mạnh chỉ với một thành phần duy nhất (không cần pha trộn), sản phẩm giúp bạn hàn gắn lại giày dép, đồ gốm sứ, đồ chơi hay các vật dụng nhựa một cách chắc chắn và thẩm mỹ chỉ trong vài giây.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EA526<br>Loại sản phẩm: Keo siêu dính / Keo 502 (Super Glue).<br>Thành phần: Keo 1 thành phần (Dùng ngay, không cần pha trộn như keo AB).<br>Quy cách: Tuýp nhỏ gọn.<br>Đơn vị tính: Chiếc (Tuýp).</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Khô nhanh siêu tốc: Chỉ cần vài giây sau khi nhỏ keo và ép chặt, mối dán sẽ khô và cố định ngay lập tức. Bạn không cần mất thời gian kẹp giữ hay chờ đợi lâu như các loại keo dán gỗ hay keo sữa thông thường.<br>Kết dính đa năng: Sản phẩm có thể dán dính trên nhiều bề mặt vật liệu khác nhau như: nhựa cứng, cao su, gốm sứ, gỗ, kim loại và da (giày dép).<br>Tiện lợi – Dễ sử dụng: Là dạng keo một thành phần, bạn chỉ cần mở nắp là dùng được ngay. Thiết kế đầu vòi nhỏ giúp bạn nhỏ keo chính xác vào các vết nứt hẹp mà không bị lem ra ngoài.<br>Mối dán bền chắc: Sau khi khô hoàn toàn, lớp keo tạo thành một liên kết cứng, chịu lực tốt, giúp vật dụng phục hồi lại công năng sử dụng.</li>\r\n<li>\r\n<p>ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm rất cần thiết trong hộp dụng cụ của:</p>\r\n<p>Gia đình: Sửa chữa giày dép bung đế, cốc chén sứt quai, đồ chơi trẻ em gãy.<br>Thợ thủ công/DIY: Lắp ráp mô hình, dán các chi tiết nhỏ.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Làm sạch và để khô bề mặt cần dán.<br>Nhỏ một lượng keo vừa đủ (không nên quá nhiều) lên một mặt.<br>Ép chặt hai mặt lại với nhau và giữ yên trong khoảng 10-30 giây để keo khô cứng.<br>Lưu ý an toàn (Quan trọng):<br>Keo dính rất nhanh và mạnh, tránh để dính vào da tay và tuyệt đối tránh xa vùng mắt.<br>Để xa tầm tay trẻ em.<br>Bảo quản:<br>Lau sạch đầu vòi sau khi dùng.<br>Đậy nắp thật kín và để nơi khô ráo, thoáng mát (tốt nhất là nơi có nhiệt độ thấp/ngăn mát tủ lạnh nếu muốn bảo quản lâu dài) để keo không bị chết (đông cứng) trong lọ.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2841,85,0,2061,'Keo siêu dính 502 Deli EA526');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2842,76,0,2062,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Dụng cụ cắt băng dính để bàn Deli E808 là vật dụng nhỏ bé nhưng giúp “nâng cấp” trải nghiệm làm việc của bạn lên đáng kể. Không còn cảnh phải dùng răng cắn hay loay hoay tìm đầu mối băng dính mỗi khi cần dùng, sản phẩm giúp bạn thao tác cắt – dán nhanh gọn, dứt khoát chỉ bằng một tay, giữ cho bàn làm việc luôn ngăn nắp và chuyên nghiệp.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: E808<br>Loại sản phẩm: Cắt băng dính để bàn (Tape Dispenser).<br>Kích thước băng dính phù hợp: Các loại cuộn nhỏ văn phòng (khổ rộng dưới 18mm, lõi nhỏ).<br>Chất liệu: Nhựa cứng chịu lực + Lưỡi cắt kim loại.<br>Màu sắc: Màu lẫn (Xanh, Đen… giao ngẫu nhiên).<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Thao tác một tay dễ dàng: Đế sản phẩm thường được thiết kế có độ nặng nhất định hoặc đệm mút ma sát cao, giúp cố định vững chắc trên mặt bàn. Bạn có thể thoải mái kéo và cắt băng dính bằng một tay mà không lo dụng cụ bị trượt hay xê dịch.<br>Lưỡi dao sắc bén: Phần lưỡi cắt răng cưa được làm từ thép không gỉ, sắc bén và bền bỉ. Giúp cắt băng dính “ngọt lịm”, đường cắt phẳng đẹp, không bị tưa hay dính bết keo.<br>Nhỏ gọn, tiết kiệm diện tích: Thiết kế bo tròn, kích thước vừa phải giúp sản phẩm không chiếm nhiều chỗ trên bàn làm việc nhưng vẫn đảm bảo đầy đủ công năng.<br>Trục xoay linh hoạt: Trục quay trơn tru giúp việc kéo băng dính ra nhẹ nhàng, không bị kẹt hay rít.</li>\r\n<li>\r\n<p> ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là trợ thủ đắc lực cho:</p>\r\n<p>Nhân viên văn phòng: Dùng để dán giấy tờ, niêm phong thư từ hàng ngày.<br>Cửa hàng gói quà/tạp hóa: Cần cắt băng dính liên tục và nhanh chóng.<br>Học sinh, Sinh viên: Hỗ trợ bọc sách vở, làm thủ công.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Lắp cuộn băng dính vào trục xoay.<br>Kéo đầu băng dính ra và đặt lên phần lưỡi cắt.<br>Khi cần dùng, kéo băng dính đến độ dài mong muốn và nhấn nhẹ xuống lưỡi răng cưa để cắt.<br>Bảo quản:<br>Nếu lưỡi dao bị dính keo lâu ngày, hãy dùng khăn tẩm chút cồn hoặc dầu máy để lau sạch, giúp dao sắc bén trở lại.<br>Để nơi khô ráo, tránh rơi vỡ mạnh làm nứt vỏ nhựa.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2843,85,0,2062,'Cắt băng dính để bàn Deli E808');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2844,76,0,2063,'<p>1. MÔ TẢ SẢN PHẨM<br>Giấy nhớ Deli EA602 là “người nhắc việc” tận tụy giúp bạn không bỏ lỡ bất kỳ thông tin quan trọng nào. Với những tờ giấy nhỏ nhắn mang màu sắc rực rỡ, bạn có thể dễ dàng ghi lại nhanh các ý tưởng, lịch hẹn hay danh sách việc cần làm và dán chúng ở bất cứ đâu trong tầm mắt. Đây là vật dụng không thể thiếu để giữ cho công việc và học tập luôn trôi chảy, ngăn nắp.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EA602<br>Loại sản phẩm: Giấy nhớ / Giấy ghi chú.<br>Kích thước: Vuông (kích thước tiêu chuẩn phổ biến).<br>Số tờ: Thường là 100 tờ/tệp.<br>Màu sắc: Vàng<br>Đơn vị tính: Tệp.</p>\r\n<p><br>3. ĐẶC ĐIỂM SẢN PHẨM<br>Lớp keo chất lượng: Dải keo ở mặt sau có độ dính tốt, giúp giấy bám chắc trên nhiều bề mặt khác nhau như màn hình máy tính, bàn làm việc, tủ lạnh, bìa sách… Đặc biệt, lớp keo này cho phép bạn bóc ra và dán lại nhiều lần mà không để lại vết keo bẩn hay làm rách bề mặt giấy tờ bên dưới.<br>Màu sắc nổi bật: Sản phẩm sử dụng các tông màu dạ quang rực rỡ, giúp tờ giấy ghi chú luôn “tỏa sáng” và thu hút sự chú ý ngay lập tức, đảm bảo bạn sẽ nhìn thấy lời nhắc nhở của mình.<br>Giấy viết êm: Bề mặt giấy mịn màng, viết rất êm tay và ăn mực. Bạn có thể sử dụng nhiều loại bút khác nhau (bút bi, bút chì, bút nước) để viết lên mà không lo bị nhòe.<br>Tiện lợi: Thiết kế nhỏ gọn giúp bạn dễ dàng mang theo trong túi xách hoặc để gọn gàng một góc trên bàn làm việc.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng thiết yếu cho mọi người:<br>Nhân viên văn phòng: Ghi chú lịch họp, số điện thoại, việc cần làm gấp.<br>Học sinh, Sinh viên: Đánh dấu trang sách, ghi chú công thức, từ vựng quan trọng.<br>Gia đình: Dán lời nhắn trên tủ lạnh, ghi danh sách đi chợ.</p>\r\n<p><br>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Viết nội dung cần ghi nhớ lên tờ giấy.<br>Bóc tờ giấy ra khỏi tệp. Mẹo nhỏ: Nên bóc tờ giấy theo chiều ngang (từ trái sang phải) thay vì bóc ngược từ dưới lên trên. Cách này giúp tờ giấy phẳng phiu, không bị cong vênh khi dán lên bề mặt khác.<br>Dán lên vị trí dễ nhìn thấy.<br>Bảo quản:<br>Để nơi khô ráo, tránh nơi ẩm ướt hoặc dầu mỡ làm giảm độ dính của keo.<br>Tránh nguồn nhiệt cao.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2845,85,0,2063,'Giấy note màu Deli EA602');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2846,76,0,2064,'<p>1. MÔ TẢ SẢN PHẨM<br>Sổ lò xo Deli EN004 là sự kết hợp hoàn hảo giữa tính tiện dụng và thẩm mỹ. Với kích thước B5 vừa vặn và gáy lò xo linh hoạt, cuốn sổ này cho phép bạn ghi chép, lật giở trang cực kỳ thoải mái mà không lo bị phồng hay cộm tay. Đây là vật dụng lý tưởng để ghi chú nhanh trong các cuộc họp, bài giảng hoặc phác thảo ý tưởng mọi lúc mọi nơi.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EN004<br>Loại sản phẩm: Sổ tay gáy lò xo.<br>Kích thước: Khổ B5 (Rộng hơn khổ A5 nhưng nhỏ gọn hơn khổ A4).<br>Số trang: 60 trang.<br>Định lượng giấy: 70gsm (Độ dày tiêu chuẩn).<br>Đơn vị tính: Quyển.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Gáy lò xo kép tiện lợi: Thiết kế gáy xoắn kép chắc chắn giúp bạn có thể mở sổ phẳng 180 độ hoặc gập ngược bìa ra sau 360 độ một cách dễ dàng. Điều này cực kỳ hữu ích khi bạn phải ghi chép trong không gian hẹp hoặc cầm sổ trên tay để viết. Ngoài ra, bạn có thể xé bỏ một trang giấy bất kỳ mà không làm ảnh hưởng đến kết cấu của các trang còn lại.<br>Giấy viết chất lượng: Với định lượng 70gsm, giấy có độ dày vừa phải, bề mặt láng mịn, bắt mực tốt và viết rất êm. Màu giấy dịu nhẹ giúp bảo vệ mắt khi làm việc lâu.<br>Kích thước B5 chuẩn mực: Khổ giấy B5 được xem là “tỷ lệ vàng” cho sổ tay ghi chép cá nhân – đủ rộng để trình bày nội dung thoải mái nhưng vẫn đủ gọn để bỏ vừa vào túi xách, balo cỡ trung.<br>Bìa sổ bền đẹp: Bìa thường được làm từ nhựa hoặc giấy bồi cứng giúp bảo vệ ruột giấy bên trong không bị quăn góc và tạo điểm tựa chắc chắn khi viết.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm phù hợp với đa dạng nhu cầu:<br>Sinh viên: Ghi chép bài giảng, làm bài tập nhóm.<br>Nhân viên văn phòng: Ghi biên bản cuộc họp, lên danh sách công việc (To-do list).<br>Người làm sáng tạo: Phác thảo ý tưởng, vẽ nháp (doodle).</p>\r\n<p>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Lật mở trang cần viết. Có thể gập bìa ra sau để tiết kiệm diện tích mặt bàn.<br>Khi cần xé giấy: Nên giữ chặt phần giấy sát gáy lò xo và xé dứt khoát để đường xé được đẹp và không làm rách giấy thừa.<br>Bảo quản:<br>Tránh đè nặng lên gáy: Không để vật quá nặng đè lên phần lò xo để tránh làm biến dạng khung kim loại, gây khó khăn khi lật trang.<br>Để nơi khô ráo, tránh ẩm ướt làm giấy bị mềm.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2847,85,0,2064,'Sổ lò xo B5 Deli EN004');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2848,76,0,2065,'<p>1. MÔ TẢ SẢN PHẨM<br>Giấy kiểm tra Deli CN602 là “người bạn đồng hành” quen thuộc giúp các bạn học sinh tiết kiệm thời gian và tự tin hơn trong mỗi giờ kiểm tra. Thay vì phải hì hụi kẻ vẽ khung điểm, lời phê hay điền thông tin thủ công, sản phẩm đã được in sẵn đầy đủ các mục cần thiết với bố cục chuẩn mực. Giấy có độ mịn cao, dòng kẻ rõ nét, giúp bài làm của bạn luôn sạch đẹp và gây thiện cảm với thầy cô.</p>\r\n<p>2. THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: CN602<br>Loại sản phẩm: Giấy kiểm tra / Giấy thi.<br>Kiểu dòng kẻ: Kẻ ngang.<br>Kích thước: 175 x 250 mm (Kích thước tiêu chuẩn của vở học sinh).<br>Đơn vị tính: Tệp.</p>\r\n<p>3. ĐẶC ĐIỂM SẢN PHẨM<br>Thiết kế tiện lợi, chuẩn quy định: Giấy được in sẵn khung điểm, lời phê của giáo viên và các dòng thông tin cá nhân (Họ tên, Lớp, Môn…) một cách rõ ràng, khoa học. Học sinh chỉ việc điền vào và làm bài ngay, không mất thời gian kẻ vẽ, giúp tập trung tối đa vào nội dung bài thi.<br>Chất giấy láng mịn: Bề mặt giấy có độ mịn cao, viết rất êm tay và “bắt” mực tốt. Dù viết bằng bút máy hay bút bi, mực xuống đều, không bị nhòe hay thấm sang mặt sau, giữ cho bài kiểm tra luôn sạch sẽ.<br>Dòng kẻ ngang sắc nét: Các đường kẻ ngang được in với độ đậm vừa phải, giúp học sinh dễ dàng căn chỉnh hàng lối, rèn chữ viết ngay ngắn, thẳng hàng.<br>Kích thước tiêu chuẩn: Với kích thước 175x250mm, giấy kiểm tra khi gấp đôi lại sẽ vừa vặn để kẹp vào vở ghi hoặc nộp bài mà không bị thừa hay thiếu hụt so với các loại giấy vở thông thường.</p>\r\n<p>4. ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng thiết yếu cho:<br>Học sinh Trung học cơ sở (Cấp 2) &amp; Trung học phổ thông (Cấp 3): Sử dụng thường xuyên cho các bài kiểm tra 15 phút, 1 tiết.<br>Sinh viên: Dùng cho các bài kiểm tra giữa kỳ, bài luận ngắn.</p>\r\n<p>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Lấy tờ giấy ra khỏi tệp.<br>Điền đầy đủ thông tin vào phần đầu phách (Họ tên, Lớp, Môn…).<br>Làm bài trực tiếp lên phần kẻ ngang.<br>Bảo quản:<br>Giữ thẳng giấy: Để giấy trong tệp hoặc kẹp hồ sơ để tránh bị quăn mép, nhàu nát.<br>Để nơi khô ráo, tránh nơi ẩm thấp làm giấy bị mềm và mực dễ bị nhòe khi viết.</p>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2849,85,0,2065,'Giấy kiểm tra Deli CN602');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2850,76,0,2066,'<ol>\r\n<li> MÔ TẢ SẢN PHẨM<br>Bộ thước Eke Deli EH600 là “bộ tứ” quyền lực giúp các bạn học sinh chinh phục môn Toán hình học một cách dễ dàng. Với đầy đủ các dụng cụ đo góc và kẻ vẽ cơ bản được đóng gói gọn gàng, sản phẩm giúp việc vẽ các hình khối, đường thẳng hay đo độ trở nên chính xác và thuận tiện hơn bao giờ hết.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EH600<br>Loại sản phẩm: Bộ thước kẻ hình học (Geometry Set).<br>Quy cách: 1 bộ (gồm 4 chi tiết: 1 Thước thẳng 15cm, 2 Thước Eke, 1 Thước đo độ).<br>Màu sắc: Màu lẫn (Nhiều màu sắc tươi sáng: Xanh, Hồng…).<br>Chất liệu: Nhựa cứng trong suốt.<br>Đơn vị tính: Bộ.</li>\r\n<li> ĐẶC ĐIỂM SẢN PHẨM<br>Combo tiện lợi: Chỉ cần mua một bộ là bé đã có đủ các dụng cụ cần thiết cho môn Toán:<br>Thước thẳng: Kẻ đường thẳng, đo độ dài.<br>Thước Eke (2 chiếc): Vẽ góc vuông, góc 45 độ, 60 độ, đường song song.<br>Thước đo độ: Đo và vẽ các góc bất kỳ.<br>Vạch chia chuẩn xác: Các vạch số và vạch chia mm được in ấn sắc nét, rõ ràng, không bị nhòe hay phai mờ, giúp học sinh quan sát và đo đạc chính xác tuyệt đối.<br>Nhựa trong an toàn: Chất liệu nhựa trong suốt giúp dễ dàng nhìn thấy hình vẽ bên dưới để căn chỉnh. Các cạnh thước được xử lý mài nhẵn, không sắc bén, đảm bảo an toàn cho tay trẻ khi sử dụng.<br>Nhỏ gọn: Kích thước các thước được thiết kế vừa vặn để bỏ chung vào túi zip đi kèm hoặc hộp bút, tránh thất lạc.</li>\r\n<li>\r\n<p>ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng bắt buộc phải có đối với:</p>\r\n<p>Học sinh cấp 1, cấp 2: Bắt đầu làm quen với các khái niệm hình học, góc, đường thẳng.<br>Giáo viên: Dùng để hướng dẫn học sinh.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Chọn loại thước phù hợp với nhu cầu (kẻ thẳng, đo góc vuông, đo độ…). Giữ cố định thước bằng tay trái và kẻ/đo bằng tay phải.<br>Bảo quản:<br>Sau khi dùng xong, nên xếp gọn vào túi đựng đi kèm để tránh làm rơi mất các chi tiết nhỏ.<br>Tránh bẻ cong thước hoặc để vật nặng đè lên làm gãy nhựa.<br>Tránh để thước cọ xát với vật sắc nhọn (compa, kéo) làm xước bề mặt số.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2851,85,0,2066,'Bộ thước Eke Deli EH600');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2852,76,0,2067,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Bút xóa băng Deli EH354 là giải pháp sửa lỗi “nhanh – gọn – sạch” cho mọi bài viết. Tạm biệt những phút giây phải ngồi thổi cho khô mực như dùng bút xóa nước truyền thống, với EH354, bạn chỉ cần lướt nhẹ một đường là có thể viết đè lên ngay lập tức. Sản phẩm giúp giữ cho dòng chảy tư duy của bạn không bị gián đoạn, đặc biệt hữu ích trong các kỳ thi hay khi cần ghi chép tốc độ cao.</li>\r\n<li>THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: EH354<br>Loại sản phẩm: Bút xóa băng / Băng xóa (Correction Tape).<br>Kích thước băng: Rộng 5mm x Dài 12m.<br>Màu sắc thân vỏ: Màu lẫn (Nhiều màu sắc đa dạng trong một hộp).<br>Đơn vị tính: Chiếc.</li>\r\n<li>ĐẶC ĐIỂM SẢN PHẨM<br>Sửa sai siêu tốc – Viết lại ngay: Công nghệ băng xóa khô giúp che phủ vết mực ngay tức thì. Bạn có thể viết đè lên ngay sau khi xóa mà không sợ mực bị nhòe hay đầu bút bị tắc, tiết kiệm thời gian quý báu.<br>Dung lượng “khủng” 12m: Mặc dù có thiết kế nhỏ gọn vừa lòng bàn tay, nhưng cuộn băng bên trong dài tới 12 mét. Đây là độ dài lý tưởng giúp bạn sử dụng được rất lâu, tiết kiệm chi phí thay mới thường xuyên.<br>Che phủ mịn màng: Lớp băng xóa mỏng, dai và bám dính tốt vào mặt giấy. Bề mặt băng mịn màng, không bị bong tróc hay đứt gãy, giúp trang giấy sau khi sửa vẫn phẳng phiu, thẩm mỹ, không để lại vết gồ ghề lớn khi photo hay scan tài liệu.<br>Kéo nhẹ, êm tay: Hệ thống bánh răng bên trong được thiết kế chính xác giúp băng ra đều, trơn tru, không bị kẹt hay rối băng khi kéo.</li>\r\n<li>\r\n<p> ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng “bất ly thân” của:</p>\r\n<p>Học sinh, Sinh viên: Cần sửa bài nhanh, sạch sẽ, đặc biệt là trong giờ kiểm tra trắc nghiệm hoặc thi viết luận.<br>Nhân viên văn phòng: Cần sự chuyên nghiệp và tốc độ khi xử lý văn bản.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng:<br>Đặt đầu bút xóa nghiêng một góc khoảng 45 độ so với mặt giấy, sát vào vị trí cần xóa.<br>Ấn nhẹ và kéo bút về phía sau để băng phủ kín phần chữ sai.<br>Đến vị trí kết thúc, nhấn nhẹ và nhấc bút lên dứt khoát (theo phương thẳng đứng) để ngắt băng.<br>Bảo quản:<br>Luôn đậy nắp bảo vệ đầu băng sau khi sử dụng để tránh bụi bẩn bám vào lớp keo hoặc băng bị xước rách.<br>Để nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp và nhiệt độ cao.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2853,85,0,2067,'Bút xóa băng Deli EH354');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2854,76,0,2068,'<ol>\r\n<li>MÔ TẢ SẢN PHẨM<br>Gọt chì Deli E0594 là “trợ thủ” nhỏ xinh nhưng vô cùng đắc lực trong hộp bút của mỗi bạn học sinh. Với thiết kế nhỏ gọn, màu sắc tươi tắn cùng lưỡi dao bén ngọt, sản phẩm giúp “hồi sinh” những chiếc bút chì đã mòn vẹt trở nên sắc nét chỉ trong vài vòng xoay, giúp nét chữ, nét vẽ luôn liền mạch và đẹp mắt.</li>\r\n<li> THÔNG SỐ KỸ THUẬT<br>Mã sản phẩm: E0594<br>Loại sản phẩm: Gọt chì cầm tay (Manual Pencil Sharpener).<br>Màu sắc: Màu lẫn (Nhiều màu sắc đa dạng trong một hộp).<br>Chất liệu: Vỏ nhựa cứng, lưỡi dao kim loại.<br>Đơn vị tính: Chiếc.</li>\r\n<li> ĐẶC ĐIỂM SẢN PHẨM<br>Lưỡi dao sắc bén: Phần lưỡi gọt được làm từ thép không gỉ chất lượng cao, có độ sắc bén duy trì lâu dài. Khi gọt, gỗ bút chì được bào mỏng nhẹ nhàng, trơn tru, hạn chế tối đa tình trạng gãy ngòi chì ở bên trong.<br>Nhỏ gọn và tiện lợi: Kích thước siêu nhỏ gọn giúp bạn dễ dàng cất nó vào bất kỳ ngăn nhỏ nào của hộp bút hay túi áo mà không tốn diện tích.<br>Dễ cầm nắm: Thiết kế vỏ ngoài thường có các đường rãnh hoặc vết lõm chống trượt, giúp tay cầm chắc chắn khi thao tác xoay bút.<br>Màu sắc đa dạng: Sản phẩm có nhiều gam màu vui tươi, phù hợp với sở thích của các bạn nhỏ.</li>\r\n<li>\r\n<p> ĐỐI TƯỢNG SỬ DỤNG<br>Sản phẩm là vật dụng cơ bản dành cho:</p>\r\n<p>Học sinh, Sinh viên: Sử dụng bút chì gỗ để viết hoặc vẽ hình.<br>Họa sĩ, Người học vẽ: Cần gọt bút chì phác thảo nhanh chóng.</p>\r\n</li>\r\n<li>CÁCH SỬ DỤNG VÀ BẢO QUẢN<br>Cách sử dụng: Cầm chắc gọt chì bằng một tay, tay kia đưa đầu bút chì vào lỗ gọt. Xoay nhẹ nhàng bút chì theo chiều kim đồng hồ cho đến khi đầu ngòi đạt độ nhọn mong muốn.<br>Lưu ý: Không nên ấn bút quá mạnh khi gọt để tránh gãy ngòi.<br>Bảo quản: Thường xuyên loại bỏ vụn gỗ dính ở lưỡi dao (nếu có) để gọt không bị kẹt. Để nơi khô ráo, tránh rơi rớt làm mẻ lưỡi dao.</li>\r\n</ol>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2855,85,0,2068,'Gọt chì Deli E0594');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2856,76,0,2069,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút Gel <strong>Deli EG057</strong> mang đến một định nghĩa mới về trải nghiệm viết êm ái. Không còn nỗi lo bút bị gai hay rít, <strong>EG057</strong> với công nghệ mực cải tiến giúp ngòi bút lướt trên giấy nhẹ nhàng như mây, để những dòng suy nghĩ của bạn tuôn chảy liên tục và đầy cảm hứng.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EG057</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút Gel (Bút bi nước).</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.5mm.</li>\r\n<li><strong>Màu mực:</strong>\r\n<ul>\r\n<li><strong>EG057-BL:</strong> Xanh dương.</li>\r\n<li><strong>EG057-BK:</strong> Đen.</li>\r\n</ul>\r\n</li>\r\n<li><strong>Đơn vị tính:</strong> Chiếc.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực “Siêu mượt”:</strong> Điểm sáng giá nhất của <strong>EG057</strong> nằm ở công thức mực đặc biệt. Mực được bổ sung thành phần đóng vai trò như chất “bôi trơn”, bao phủ các hạt mực để giảm thiểu tối đa lực ma sát giữa ngòi bút và mặt giấy. Kết quả là bạn sẽ cảm nhận được độ trơn tru vượt trội, viết lâu không bị mỏi tay. Thêm vào đó, mực còn có khả năng khô cực nhanh, giúp trang giấy luôn sạch sẽ, không lo bị lem hay nhòe khi viết.</li>\r\n<li><strong>Nét viết sắc sảo:</strong> Kích thước ngòi 0.5mm tiêu chuẩn tạo ra nét chữ thanh mảnh, gọn gàng, phù hợp cho mọi loại văn bản từ ghi chép học tập đến ký tên văn phòng.</li>\r\n<li><strong>Mực ra đều đặn:</strong> Nhờ yếu tố bôi trơn kết hợp cùng lõi dẫn chất lượng cao, dòng mực chảy xuống đầu ngòi luôn ổn định, mịn màng và liên tục. Sự kết hợp này giúp hạn chế tối đa tình trạng tắc mực hay đứt nét giữa chừng, mang lại trải nghiệm viết hoàn toàn trơn tru.</li>\r\n<li><strong>Thiết kế tiện dụng:</strong> Thân bút chắc chắn, dễ cầm nắm, giúp người dùng thao tác linh hoạt.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm là lựa chọn lý tưởng cho:</p>\r\n<ul>\r\n<li><strong>Học sinh, Sinh viên:</strong> Cần viết bài nhanh, nhiều và liên tục, cần một cây bút viết “bay” chữ để kịp bài giảng.</li>\r\n<li><strong>Nhân viên văn phòng:</strong> Yêu thích cảm giác viết nhẹ nhàng, không tốn sức.</li>\r\n<li><strong>Người hay ghi chép:</strong> Cần sự thoải mái tối đa khi cầm bút.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Mở nắp (hoặc bấm) và viết trực tiếp lên giấy. Với bút mới, nhớ gỡ bỏ hạt sáp bảo vệ ở đầu ngòi (nếu có).</li>\r\n<li><strong>Bảo quản:</strong> Đậy nắp kín hoặc thu ngòi về ngay sau khi sử dụng để tránh khô mực. Tránh làm rơi bút cắm đầu xuống đất gây hỏng bi ở ngòi.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2857,85,0,2069,'Bút gel bấm siêu trơn Deli EG575');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2858,76,0,2070,'<h3 style=\"text-align: justify;\"><strong>1. MÔ TẢ SẢN PHẨM</strong></h3>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Bút gel bấm siêu mượt </span><strong>Deli EG118</strong><span style=\"font-weight: 400;\"> là người bạn đồng hành lý tưởng cho những ai yêu thích sự êm ái khi viết lách. Với công nghệ mực cải tiến đặc biệt, cây bút mang lại cảm giác lướt nhẹ nhàng trên mặt giấy, giúp nét chữ trở nên bay bổng và công việc ghi chép hàng ngày trở nên thú vị hơn bao giờ hết.</span></p>\r\n<h3 style=\"text-align: justify;\"><strong>2. THÔNG SỐ KỸ THUẬT</strong></h3>\r\n<ul style=\"text-align: justify;\">\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Mã sản phẩm:</strong><span style=\"font-weight: 400;\"> EG118</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Loại sản phẩm:</strong><span style=\"font-weight: 400;\"> Bút bi mực gel (Dạng bấm).</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Kích thước ngòi:</strong><span style=\"font-weight: 400;\"> 0.5mm.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Màu mực:</strong><span style=\"font-weight: 400;\"> Xanh dương, Đen, Đỏ, Tím, Xanh nhạt.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Đơn vị tính:</strong><span style=\"font-weight: 400;\"> Chiếc.</span></li>\r\n</ul>\r\n<h3 style=\"text-align: justify;\"><strong>3. ĐẶC ĐIỂM SẢN PHẨM</strong></h3>\r\n<ul style=\"text-align: justify;\">\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Công nghệ mực “siêu mượt”:</strong><span style=\"font-weight: 400;\"> Điểm đặc biệt nhất của dòng bút này là mực được bổ sung thành phần bôi trơn chuyên dụng. Yếu tố này bao phủ các hạt màu, giúp giảm đáng kể ma sát giữa đầu bút và giấy, cho trải nghiệm viết trơn tru vượt trội so với bút gel thông thường. Đặc biệt, bút còn có độ bền ấn tượng với lượng mực dồi dào, hỗ trợ bạn viết liên tục trên quãng đường dài tới 400m.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Nét viết thanh mảnh:</strong><span style=\"font-weight: 400;\"> Đầu bi 0.5mm tạo ra những đường nét gọn gàng, sắc sảo, rất phù hợp để viết các chi tiết nhỏ hoặc ký tên. Điểm cộng lớn là cảm giác viết rất êm tay nhờ mực ra đều và liền mạch, không lo bị đứt nét hay tắc mực giữa chừng.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Thiết kế tiện dụng:</strong><span style=\"font-weight: 400;\"> Cơ chế bấm lò xo nhạy bén giúp bảo vệ ngòi bút nhanh chóng chỉ với một thao tác, không lo thất lạc nắp bút.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Màu sắc phong phú:</strong><span style=\"font-weight: 400;\"> Ngoài các màu cơ bản (Xanh, Đen, Đỏ), bộ sưu tập còn có thêm màu Tím và Xanh nhạt, giúp bạn thỏa sức sáng tạo và phân loại nội dung ghi chú hiệu quả.</span></li>\r\n</ul>\r\n<h3 style=\"text-align: justify;\"><strong>4. ĐỐI TƯỢNG SỬ DỤNG</strong></h3>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Sản phẩm rất thích hợp cho:</span></p>\r\n<ul style=\"text-align: justify;\">\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Học sinh, sinh viên cần bút viết trơn để chép bài nhanh và nhiều.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Nhân viên văn phòng dùng để ghi chú công việc, lên ý tưởng.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Những người yêu thích viết bullet journal hoặc trang trí sổ tay.</span></li>\r\n</ul>\r\n<h3 style=\"text-align: justify;\"><strong>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></h3>\r\n<ul>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><strong>Cách sử dụng:</strong><span style=\"font-weight: 400;\"> Bấm nhẹ đuôi bút để ngòi lộ ra khi bắt đầu viết. Sau khi dùng xong, hãy bấm lại để thu ngòi về nhằm bảo vệ mực không bị khô.</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><strong>Bảo quản:</strong><span style=\"font-weight: 400;\"> Nên để bút ở nơi khô ráo, tránh ánh nắng trực tiếp. Hạn chế làm rơi bút, đặc biệt là rơi cắm đầu xuống đất để tránh làm hỏng bi bút khiến mực ra không đều.</span></li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2859,85,0,2070,'Bút Gel bấm Deli EG118');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2860,76,0,2071,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi <strong>Deli EQ70</strong> là sự kết hợp hoàn hảo giữa thiết kế hiện đại và trải nghiệm viết “lướt” êm ái. Nhờ ứng dụng công nghệ mực Đức tiên tiến cùng đầu ngòi Thụy Sĩ bền bỉ, <strong>EQ70</strong> mang lại cảm giác thoải mái tối đa, giúp từng nét chữ của bạn trở nên đều đặn và công việc ghi chép hàng ngày trở nên nhẹ nhàng hơn bao giờ hết.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EQ70</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút bi mực dầu.</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Xanh dương.</li>\r\n<li><strong>Đơn vị tính:</strong> Chiếc.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực Đức (Độ nhớt thấp):</strong> Mực của <strong>Deli EQ70</strong> được phát triển đặc biệt để có độ lỏng lý tưởng. Điều này giúp mực chảy xuống đầu bút một cách tự nhiên, giảm ma sát tối đa với giấy, cho phép bạn viết nhanh mà không cần tì mạnh tay.</li>\r\n<li><strong>Đầu ngòi Thụy Sĩ (AFIT):</strong> Sử dụng ngòi bút từ thương hiệu Premec danh tiếng, đảm bảo viên bi lăn trơn tru và ổn định. Bạn sẽ không gặp phải tình trạng mực bị tắc hay đọng lại ở đầu ngòi gây lem luốc.</li>\r\n<li><strong>Nét viết đậm rõ:</strong> Kích thước ngòi 0.7mm tạo ra nét chữ đậm đà, dễ nhìn, rất thích hợp cho việc ký tên hoặc ghi chép các văn bản cần sự rõ ràng.</li>\r\n<li><strong>Miếng đệm tay cầm êm ái:</strong> Thiết kế thêm đệm cao su với tiết diện hình tam giác vừa vặn, giúp chống trơn tuột và đảm bảo sự thoải mái tối đa ngay cả khi phải viết thường xuyên.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm phù hợp với đa dạng nhu cầu:</p>\r\n<ul>\r\n<li><strong>Nhân viên văn phòng, Quản lý:</strong> Dùng để ký kết hợp đồng, phê duyệt văn bản.</li>\r\n<li><strong>Học sinh, Sinh viên:</strong> Cần một cây bút viết trơn, đều mực để chép bài nhanh.</li>\r\n<li><strong>Cơ quan, Ngân hàng:</strong> Trang bị tại các quầy giao dịch phục vụ khách hàng.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Bấm nhẹ đuôi bút để ngòi lộ ra và viết trực tiếp lên giấy. Bấm lại để thu ngòi về sau khi sử dụng để bảo vệ mực.</li>\r\n<li><strong>Bảo quản:</strong> Để bút ở nơi khô ráo, thoáng mát. Tránh để nơi có nhiệt độ quá cao làm chảy mực. Hạn chế làm rơi bút, đặc biệt là rơi cắm đầu xuống đất để tránh hỏng bi.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2861,85,0,2071,'Bút bi Deli EQ70-BL');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2862,76,0,2072,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút gel <strong>Deli CQ29-BK</strong> (màu đen) là sự lựa chọn hàng đầu cho những ai yêu thích sự chuyên nghiệp và chỉn chu. Nhờ sự kết hợp hoàn hảo giữa công nghệ mực Đức và đầu ngòi Thụy Sĩ, sản phẩm mang lại cảm giác viết êm ái, nhẹ nhàng, giúp nét chữ của bạn luôn sắc sảo trên mọi loại giấy tờ, văn bản.</p>\r\n<ol start=\"2\">\r\n<li><strong>THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> CQ29-BK</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút gel</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Đen.</li>\r\n<li><strong>Đơn vị tính:</strong> Chiếc.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực Đức (Độ nhớt thấp):</strong> Mực của <strong>Deli CQ29-BK</strong> được pha chế với công thức đặc biệt giúp dòng chảy cực kỳ mượt mà. Ma sát giữa bút và giấy được giảm xuống mức thấp nhất, cho phép bạn viết nhanh, lướt nhẹ mà không cần tì tay mạnh.</li>\r\n<li><strong>Đầu ngòi Thụy Sĩ (AFIT):</strong> Sử dụng ngòi bút Premec nổi tiếng, đảm bảo viên bi lăn đều và ổn định. Mực ra liên tục, hạn chế tối đa tình trạng tắc nghẽn hay đọng mực ở đầu ngòi, giữ cho trang giấy luôn sạch đẹp.</li>\r\n<li><strong>Sắc đen chuẩn mực:</strong> Màu mực đen đậm, rõ nét và khô nhanh, rất phù hợp dùng để ký kết hợp đồng, văn bản hành chính hoặc ghi chép các thông tin quan trọng cần độ tương phản cao.</li>\r\n<li><strong>Miếng đệm tay cầm êm ái:</strong> Thiết kế thêm đệm cao su giúp chống trơn trượt, cầm chắc tay và mang lại sự thoải mái tối đa trong suốt quá trình sử dụng.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm đặc biệt phù hợp cho:</p>\r\n<ul>\r\n<li><strong>Nhân viên văn phòng, Quản lý:</strong> Dùng để ký tên, phê duyệt giấy tờ, hợp đồng.</li>\r\n<li><strong>Giáo viên, Giám thị:</strong> Sử dụng trong công tác chấm thi, ghi chép hồ sơ.</li>\r\n<li><strong>Học sinh, Sinh viên:</strong> Dùng trong các kỳ thi cử quan trọng yêu cầu mực đen.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Bấm nhẹ đuôi bút để ngòi lộ ra và viết trực tiếp. Bấm lại để thu ngòi về ngay sau khi sử dụng để bảo vệ mực.</li>\r\n<li><strong>Bảo quản:</strong> Để nơi khô ráo, thoáng mát. Tránh nhiệt độ quá cao làm chảy mực. Hạn chế làm rơi bút cắm đầu xuống đất để tránh hỏng bi bút.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2863,85,0,2072,'Bút bi Deli CQ29-BK');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2864,76,0,2073,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi 4 màu <strong>Deli EQ182</strong> là giải pháp “tất cả trong một” cực kỳ tiện lợi cho công việc và học tập. Thay vì phải mang theo nhiều cây bút lỉnh kỉnh, giờ đây bạn chỉ cần một sản phẩm duy nhất để linh hoạt chuyển đổi giữa các màu mực. Kết hợp với công nghệ mực Đức êm ái, EQ182 giúp việc ghi chép, đánh dấu và phân loại thông tin trở nên nhanh chóng, khoa học hơn bao giờ hết.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EQ182</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút bi dầu (tích hợp 4 ngòi).</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> 4 màu trong 1 bút (Xanh, Đen, Đỏ, Xanh lá).</li>\r\n<li><strong>Đơn vị tính:</strong> Chiếc.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Thiết kế thông minh 4 trong 1:</strong> Tích hợp 4 ruột bút với 4 màu mực khác nhau trong cùng một thân bút gọn nhẹ. Cơ chế lò xo nhạy bén giúp bạn chuyển đổi màu sắc tức thì chỉ bằng một thao tác gạt tay đơn giản.</li>\r\n<li><strong>Công nghệ mực Đức (Độ nhớt thấp):</strong> Mực bút được tối ưu hóa để có độ lỏng vừa phải, giảm ma sát tối đa khi viết. Bạn sẽ cảm nhận được sự trơn tru, nhẹ nhàng, mực xuống đều mà không cần ấn mạnh.</li>\r\n<li><strong>Ngòi bút AFIT (Thụy Sĩ):</strong> Đầu bi cao cấp từ Premec đảm bảo độ bền bỉ và ổn định. Ngòi bút xoay trơn, hạn chế tắc mực và giữ cho nét chữ luôn đều đặn, sạch sẽ.</li>\r\n<li><strong>Tay cầm thoải mái:</strong> Thân bút có kích thước vừa vặn, phần tay cầm được thiết kế để chống trơn trượt, giúp bạn cầm chắc chắn ngay cả khi viết lâu.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm là trợ thủ đắc lực cho:</p>\r\n<ul>\r\n<li><strong>Giáo viên:</strong> Tiện lợi trong việc chấm bài, sửa lỗi và ghi chú bên lề.</li>\r\n<li><strong>Học sinh, sinh viên:</strong> Hỗ trợ vẽ sơ đồ tư duy (Mindmap), đánh dấu các mục quan trọng trong bài học.</li>\r\n<li><strong>Nhân viên y tế:</strong> Ghi chép hồ sơ bệnh án, trực ca cần phân biệt các loại thông tin bằng màu sắc.</li>\r\n<li><strong>Nhân viên văn phòng:</strong> Ghi chú lịch trình, phân loại công việc ưu tiên.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Gạt nút có màu tương ứng xuống để sử dụng màu mực đó. Để đổi màu, chỉ cần gạt nút màu khác xuống (nút cũ sẽ tự động nảy lên).</li>\r\n<li><strong>Bảo quản:</strong> Bảo quản ở nơi khô ráo, tránh nguồn nhiệt cao. Hạn chế làm rơi mạnh để tránh kẹt lò xo chuyển màu hoặc hỏng đầu bi.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2865,85,0,2073,'Bút bi 4 màu Deli EQ182');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2866,76,0,2074,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi dầu <strong>Deli EQ03236</strong> là giải pháp văn phòng phẩm kinh tế và chất lượng cao, đặc biệt phù hợp cho nhu cầu sử dụng thường xuyên. Với sự kết hợp giữa công nghệ mực Đức êm ái và đầu ngòi Thụy Sĩ bền bỉ, sản phẩm giúp việc ghi chép trở nên nhẹ nhàng, trơn tru. Quy cách đóng lọ 50 chiếc cực kỳ tiện lợi để để bàn hoặc trang bị cho cả văn phòng.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EQ03236</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút bi mực dầu.</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Xanh dương.</li>\r\n<li><strong>Quy cách đóng gói:</strong> 50 chiếc/lọ.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực Đức (Độ nhớt thấp):</strong> Mực bút được pha chế đặc biệt giúp giảm tối đa ma sát khi tiếp xúc với giấy. Mực chảy xuống đều và nhanh, giúp bạn viết lướt nhẹ nhàng mà không cần dùng nhiều lực tay.</li>\r\n<li><strong>Đầu ngòi AFIT (Thụy Sĩ):</strong> Sản phẩm sử dụng ngòi bút từ thương hiệu Premec danh tiếng, đảm bảo độ ổn định tuyệt vời. Bi lăn trơn, hạn chế tình trạng tắc mực hay đọng mực ở đầu ngòi, giữ cho trang vở luôn sạch đẹp.</li>\r\n<li><strong>Nét viết đậm đà:</strong> Kích thước ngòi 0.7mm tạo ra nét chữ rõ ràng, dễ đọc, rất lý tưởng để ký tên hoặc ghi chép các thông tin quan trọng.</li>\r\n<li><strong>Tiết kiệm và Tiện lợi:</strong> Đóng gói dạng lọ 50 chiếc giúp dễ dàng bảo quản, tránh thất lạc và tiết kiệm chi phí đáng kể so với mua lẻ.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm là lựa chọn tối ưu cho:</p>\r\n<ul>\r\n<li>Các doanh nghiệp, cơ quan mua sắm văn phòng phẩm số lượng lớn cho nhân viên.</li>\r\n<li>Trường học, trung tâm đào tạo trang bị cho giáo viên và học sinh.</li>\r\n<li>Các quầy giao dịch, lễ tân, ngân hàng phục vụ khách hàng.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Mở nắp (hoặc bấm) để ngòi lộ ra và viết trực tiếp lên giấy.</li>\r\n<li><strong>Bảo quản:</strong> Bảo quản ở nhiệt độ thường, nơi khô ráo. Sau khi sử dụng nên cắm lại vào lọ hoặc hộp bút để tránh thất lạc và bảo vệ ngòi bút.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2867,76,0,2075,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi dầu <strong>Deli EQ02836</strong> là giải pháp văn phòng phẩm kinh tế và chất lượng cao. Với sự kết hợp giữa công nghệ mực tiên tiến của Đức và đầu ngòi Thụy Sĩ, sản phẩm mang lại trải nghiệm viết trơn mượt ấn tượng. Quy cách đóng lọ 50 chiếc cực kỳ tiện lợi, đáp ứng nhu cầu sử dụng lớn tại các văn phòng và trường học.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EQ02836</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút bi mực dầu.</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Xanh dương.</li>\r\n<li><strong>Quy cách đóng gói:</strong> 50 chiếc/lọ.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực độ nhớt thấp (Đức):</strong> Mực bút được pha chế đặc biệt giúp giảm ma sát tối đa khi tiếp xúc với giấy. Mực chảy đều, nhẹ nhàng, giúp bạn viết nhanh mà không cảm thấy mỏi tay hay rít ngòi.</li>\r\n<li><strong>Đầu ngòi AFIT (Thụy Sĩ):</strong> Sử dụng ngòi bút từ thương hiệu Premec nổi tiếng, <strong>Deli EQ02836</strong> đảm bảo độ ổn định cao, hạn chế tình trạng tắc mực hoặc đọng mực ở đầu bi, cho nét chữ luôn sạch sẽ.</li>\r\n<li><strong>Nét viết đậm rõ:</strong> Kích thước ngòi 0.7mm tạo ra nét chữ đậm đà, rõ ràng, rất thích hợp để ký tên hoặc ghi chép các thông tin quan trọng.</li>\r\n<li><strong>Tiết kiệm tối ưu:</strong> Thiết kế đơn giản, tập trung vào công năng và đóng gói dạng lọ lớn giúp tối ưu chi phí cho người dùng có nhu cầu lớn.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm là lựa chọn hoàn hảo cho:</p>\r\n<ul>\r\n<li>Các văn phòng công ty, doanh nghiệp cấp phát cho nhân viên.</li>\r\n<li>Trường học, trung tâm giáo dục trang bị cho giáo viên, học sinh.</li>\r\n<li>Quầy lễ tân, ngân hàng, bưu điện phục vụ khách hàng ghi chép.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Bấm nhẹ (hoặc mở nắp) để ngòi lộ ra và viết trực tiếp lên giấy. Thu ngòi về sau khi sử dụng để bảo vệ mực.</li>\r\n<li><strong>Bảo quản:</strong> Để bút ở nơi khô ráo, thoáng mát. Tránh nguồn nhiệt cao gây chảy mực. Vì là dạng lọ, nên để lọ bút ở vị trí cố định, tránh làm đổ.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2868,76,0,2076,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi <strong>Deli CQ29-BL</strong> mang đến trải nghiệm viết êm ái vượt trội nhờ sự kết hợp tinh tế giữa công nghệ mực của Đức và đầu ngòi Thụy Sĩ. Sản phẩm giúp bạn viết lách nhẹ nhàng, trơn tru mà không cần dùng nhiều lực, biến việc ghi chép hàng ngày trở nên thoải mái và hiệu quả hơn.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> CQ29-BL</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút gel.</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Xanh dương.</li>\r\n<li><strong>Đơn vị tính:</strong> Chiếc.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mực độ nhớt thấp (Công nghệ Đức):</strong> Dòng mực được phát triển đặc biệt giúp giảm tối đa ma sát. Mực chảy đều và nhẹ, cho phép bút lướt trên giấy một cách mượt mà, hạn chế tình trạng rít ngòi thường thấy ở các loại bút bi thông thường.</li>\r\n<li><strong>Ngòi bút AFIT (Thụy Sĩ):</strong> Sử dụng đầu ngòi cao cấp từ thương hiệu Premec danh tiếng, đảm bảo độ ổn định cao khi viết. Mực ra liên tục, không bị đứt quãng hay đọng mực ở đầu bi.</li>\r\n<li><strong>Nét viết đậm rõ:</strong> Kích thước ngòi 0.7mm tạo ra nét chữ đậm đà, rõ ràng, rất lý tưởng để ký tên hoặc ghi chép các thông tin quan trọng.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm phù hợp với đa dạng nhu cầu:</p>\r\n<ul>\r\n<li>Nhân viên văn phòng cần bút ký tên trơn mượt, rõ nét.</li>\r\n<li>Học sinh, sinh viên viết bài giảng.</li>\r\n<li>Các cửa hàng, doanh nghiệp sử dụng cho khách hàng ghi thông tin.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Bấm nhẹ đuôi bút để ngòi lộ ra và viết trực tiếp lên giấy. Bấm lại để thu ngòi về sau khi sử dụng xong.</li>\r\n<li><strong>Bảo quản:</strong> Để bút ở nơi khô ráo, thoáng mát. Tránh để nơi có nhiệt độ quá cao làm chảy mực. Hạn chế làm rơi bút để bảo vệ đầu bi hoạt động tốt nhất.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2869,76,0,2077,'<ol>\r\n<li><strong> MÔ TẢ SẢN PHẨM</strong></li>\r\n</ol>\r\n<p>Bút bi dầu <strong>Deli EQ03336</strong> là sự kết hợp hoàn hảo giữa công nghệ mực tiên tiến của Đức và kỹ thuật chế tác ngòi bút tinh xảo từ Thụy Sĩ. Sản phẩm mang đến trải nghiệm viết “lướt” trên giấy cực kỳ êm ái, giúp nét chữ luôn đều đặn và công việc ghi chép trở nên nhẹ nhàng, hiệu quả hơn.</p>\r\n<ol start=\"2\">\r\n<li><strong> THÔNG SỐ KỸ THUẬT</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Mã sản phẩm:</strong> EQ03336</li>\r\n<li><strong>Loại sản phẩm:</strong> Bút bi mực dầu.</li>\r\n<li><strong>Kích thước ngòi:</strong> 0.7mm.</li>\r\n<li><strong>Màu mực:</strong> Xanh dương.</li>\r\n<li><strong>Quy cách đóng gói:</strong> 50 chiếc/lọ.</li>\r\n</ul>\r\n<ol start=\"3\">\r\n<li><strong> ĐẶC ĐIỂM SẢN PHẨM</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Công nghệ mực độ nhớt thấp:</strong> Áp dụng công nghệ từ Đức, mực bút có độ loãng lý tưởng giúp dòng chảy mượt mà, giảm thiểu tối đa ma sát giữa bút và giấy. Bạn không cần ấn mạnh tay mà mực vẫn ra đều và đậm.</li>\r\n<li><strong>Đầu ngòi cao cấp:</strong> Sản phẩm sử dụng ngòi AFIT từ thương hiệu Premec (Thụy Sĩ). Đây là yếu tố then chốt giúp bút hoạt động ổn định, bền bỉ, hạn chế tình trạng tắc mực hay đọng mực ở đầu ngòi.</li>\r\n<li><strong>Nét viết rõ ràng:</strong> Kích thước ngòi 0.7mm tạo ra nét chữ đậm, rõ nét, rất thích hợp cho việc ký tên hoặc ghi chép nhanh.</li>\r\n<li><strong>Tiết kiệm tối ưu:</strong> óng gói dạng lọ 50 chiếc tiện lợi và kinh tế, phù hợp cho nhu cầu sử dụng số lượng lớn.</li>\r\n</ul>\r\n<ol start=\"4\">\r\n<li><strong> ĐỐI TƯỢNG SỬ DỤNG</strong></li>\r\n</ol>\r\n<p>Sản phẩm là lựa chọn kinh tế và chất lượng cho:</p>\r\n<ul>\r\n<li>Các doanh nghiệp, văn phòng cần trang bị bút viết số lượng lớn cho nhân viên.</li>\r\n<li>Trường học, trung tâm giáo dục phục vụ giáo viên và học sinh.</li>\r\n<li>Các cửa hàng, quầy lễ tân sử dụng để khách hàng ghi thông tin.</li>\r\n</ul>\r\n<ol start=\"5\">\r\n<li><strong> CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></li>\r\n</ol>\r\n<ul>\r\n<li><strong>Cách sử dụng:</strong> Mở nắp (hoặc bấm) để viết trực tiếp lên giấy. Mực ra đều ngay từ nét bút đầu tiên.</li>\r\n<li><strong>Bảo quản:</strong> Bảo quản ở nhiệt độ phòng, nơi khô ráo. Tránh nguồn nhiệt quá cao gây chảy mực. Đậy nắp hoặc thu ngòi sau khi sử dụng để tránh khô đầu bi.</li>\r\n</ul>');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2870,85,0,2077,'Bút bi dầu Deli EQ03336');
INSERT INTO `catalog_product_entity_text` (`value_id`, `attribute_id`, `store_id`, `entity_id`, `value`) VALUES (2871,76,0,2078,'<h3><strong>1. MÔ TẢ SẢN PHẨM</strong></h3>\r\n<p><span style=\"font-weight: 400;\">Bút máy </span><strong>Deli CQ896</strong><span style=\"font-weight: 400;\"> được thiết kế chuyên biệt để giúp các bạn học sinh tiểu học vượt qua những khó khăn ban đầu khi tập viết bút mực. Với trọng lượng nhẹ và ngòi bút trơn mượt, sản phẩm giúp bé điều khiển nét bút dễ dàng, tạo nên những trang vở sạch đẹp mà không lo lấm bẩn hay mỏi tay.</span></p>\r\n<h3><strong>2. THÔNG SỐ KỸ THUẬT</strong></h3>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Mã sản phẩm:</strong><span style=\"font-weight: 400;\"> CQ896</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Loại sản phẩm:</strong><span style=\"font-weight: 400;\"> Bút máy học sinh.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Quy cách đóng gói:</strong><span style=\"font-weight: 400;\"> 12 chiếc/hộp.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Đơn vị tính:</strong><span style=\"font-weight: 400;\"> Chiếc.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Chất liệu:</strong><span style=\"font-weight: 400;\"> Nhựa cao cấp, ngòi kim loại.</span></li>\r\n</ul>\r\n<h3><strong>3. ĐẶC ĐIỂM SẢN PHẨM</strong></h3>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Ngòi bút êm ái:</strong><span style=\"font-weight: 400;\"> Ngòi bút được gia công tỉ mỉ để mực xuống đều, tạo cảm giác viết trơn tru. Bé không cần ấn mạnh, giúp hạn chế làm rách giấy và giữ nét chữ luôn thanh thoát.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Thiết kế định vị tay cầm:</strong><span style=\"font-weight: 400;\"> Phần tay cầm được thiết kế vát định hình, giúp hướng dẫn ngón tay bé đặt đúng vị trí một cách tự nhiên. Điều này cực kỳ quan trọng để rèn tư thế cầm bút chuẩn và chống mỏi tay khi viết bài dài.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Hệ thống dẫn mực thông minh:</strong><span style=\"font-weight: 400;\"> Bút kiểm soát lượng mực ra ổn định, hạn chế tối đa tình trạng tắc mực hoặc “ộc” mực gây bẩn tay và vở.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Bền bỉ và an toàn:</strong><span style=\"font-weight: 400;\"> Thân bút làm từ nhựa chịu lực tốt, an toàn cho sức khỏe, chịu được các va đập nhẹ trong quá trình sử dụng của trẻ nhỏ.</span></li>\r\n</ul>\r\n<h3><strong>4. ĐỐI TƯỢNG SỬ DỤNG</strong></h3>\r\n<p><span style=\"font-weight: 400;\">Sản phẩm là lựa chọn hàng đầu cho:</span></p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Học sinh tiểu học:</strong><span style=\"font-weight: 400;\"> Các bé lớp 1, lớp 2 bắt đầu chuyển từ bút chì sang bút máy.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Học sinh luyện chữ:</strong><span style=\"font-weight: 400;\"> Cần cây bút nhẹ, dễ cầm để luyện các nét cơ bản.</span></li>\r\n</ul>\r\n<h3><strong>5. CÁCH SỬ DỤNG VÀ BẢO QUẢN</strong></h3>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Cách sử dụng:</strong><span style=\"font-weight: 400;\"> Bơm mực (hoặc lắp ống mực) vào thân bút. Khi viết, để bút nghiêng một góc khoảng 45 độ so với mặt giấy.</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><strong>Bảo quản:</strong><span style=\"font-weight: 400;\"> Đậy nắp ngay sau khi sử dụng để bảo vệ ngòi và giữ ẩm cho mực. Nếu để lâu không dùng, nên rửa sạch bút bằng nước ấm để tránh mực khô đóng cặn làm tắc bút.</span></li>\r\n</ul>');
