INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (20,'Footer Top Newsletter','et_footer_top_newsletter','<div class=\"top-newsletter\">\n    <div class=\"page-main\">\n        <div class=\"section-title\">\n            <span>Latest From <i>Etrend</i></span>\n        </div>\n        <div class=\"section-content\">\n            <p>\n                Subscribe to our newsletter to get exclusive discounts and new theme launches right in your inbox.\n            </p>\n            {{block class=\"Magento\\Newsletter\\Block\\Subscribe\" name=\"theme.form.subscribe\" as=\"theme.form.subscribe\" template=\"Magento_Newsletter::subscribe.phtml\"}}\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
