INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (23,'Footer Quick Links','et_footer_quicklinks','<div class=\"title\">\n    Quick Links\n</div>\n<div class=\"content\">\n    <ul>\n        <li>\n            <a href=\"{{store url=\'privacy-policy-cookie-restriction-mode\'}}\">\n                Privacy and Cookie Policy\n            </a>\n        </li>\n        <li>\n            <a href=\"{{store url=\'search/term/popular\'}}\">\n                Search Terms\n            </a>\n        </li>\n        <li>\n            <a href=\"{{store url=\'contact\'}}\">\n                Contact Us\n            </a>\n        </li>\n        <li>\n            <a href=\"{{store url=\'sales/guest/form\'}}\">\n                Orders and Returns\n            </a>\n        </li>\n        <li>\n            <a href=\"{{store url=\'catalogsearch/advanced\'}}\" data-action=\"advanced-search\">\n                Advanced Search\n            </a>\n        </li>\n    </ul>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
