INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (26,'Payment Icons','et_payment_icons','<ul class=\"payment-icons\">\n    <li><img src=\"{{media url=\'etrend/payment/amex.png\'}}\" alt=\"Amex\" /></li>\n    <li><img src=\"{{media url=\'etrend/payment/mastercard.png\'}}\" alt=\"Master Card\" /></li>\n    <li><img src=\"{{media url=\'etrend/payment/paypal.png\'}}\" alt=\"Paypal\" /></li>\n    <li><img src=\"{{media url=\'etrend/payment/visa.png\'}}\" alt=\"Visa\" /></li>\n</ul>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (27,'Home slider','et_home_slider','<div class=\"slider-wrapper\">\n    <div class=\"content-main \">\n        <div id=\"home-slider\" class=\"slides owl-carousel owl-theme\">\n            <div class=\"item\" style=\" background: url({{media url=\'bannerslider/image/slide1.jpg\'}}) center center no-repeat; background-size: cover; background-repeat: no-repeat;\">\n                <a class=\"banner-link\" href=\"#\" title=\"Slide 1\"></a>\n                <img class=\"slide-hidden-img\" src=\"{{media url=\'bannerslider/image/slide1.jpg\'}}\" alt=\"Slide 1\">\n                <div class=\"slide-content  page-main\">\n                    <div class=\"text-content left\">\n                        <h2>\n                            Up to <span>40%</span><br>\n                            <strong>DISCOUNT</strong><br>\n                            on Fashion<br>\n                            Brands\n                        </h2>\n                        <a href=\"#\" class=\"action primary\">Shop Now</a> \n                    </div>\n                </div>\n            </div>\n            <div class=\"item\" style=\" background: url({{media url=\'bannerslider/image/slide2.jpg\'}}) center center no-repeat; background-size: cover; background-repeat: no-repeat;\">\n                <img class=\"slide-hidden-img\" src=\"{{media url=\'bannerslider/image/slide2.jpg\'}}\" alt=\"Slide 2\">\n                <div class=\"slide-content  page-main\">\n                    <div class=\"text-content right\">\n                        <h2>\n                            Up to <span>40%</span><br>\n                            <strong>DISCOUNT</strong><br>\n                            on Fashion<br>\n                            Brands\n                        </h2>\n                        <a href=\"#\" class=\"action primary\">Shop Now</a>\n                    </div>\n                </div>\n            </div>\n            <div class=\"item\" style=\" background: url({{media url=\'bannerslider/image/slide3.jpg\'}}) center center no-repeat; background-size: cover; background-repeat: no-repeat;\">\n                <img class=\"slide-hidden-img\" src=\"{{media url=\'bannerslider/image/slide3.jpg\'}}\" alt=\"Slide 3\">\n                <div class=\"slide-content  page-main\">\n                    <div class=\"text-content right\">\n                        <h2>\n                            Up to <span>40%</span><br>\n                            <strong>DISCOUNT</strong><br>\n                            on Fashion<br>\n                            Brands\n                        </h2>\n                        <a href=\"#\" class=\"action primary\">Shop Now</a>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (28,'Home Services','et_home_services','<div class=\"home-services\">\n    <div class=\"page-main\">\n        <div class=\"item-row\">\n            <div class=\"item\">\n                <div class=\"item-inner\">\n                    <div class=\"icon\">\n                        <img src=\"{{media url=\'etrend/home/online-support.png\'}}\" alt=\"24/7 Online Support\" />\n                    </div>\n                    <div class=\"text\">\n                        <strong>\n                            24/7 Online Support\n                        </strong>\n                        <p>\n                            Trained stufs are ready to help 24/7\n                        </p>\n                    </div>\n                </div>\n            </div>\n            <div class=\"item\">\n                <div class=\"item-inner\">\n                    <div class=\"icon\">\n                        <img src=\"{{media url=\'etrend/home/money-back.png\'}}\" alt=\"Money Back Guarantee\" />\n                    </div>\n                    <div class=\"text\">\n                        <strong>\n                            Money Back Guarantee\n                        </strong>\n                        <p>\n                            100% money back guarantee\n                        </p>\n                    </div>\n                </div>\n            </div>\n            <div class=\"item\">\n                <div class=\"item-inner\">\n                    <div class=\"icon\">\n                        <img src=\"{{media url=\'etrend/home/free-shipping.png\'}}\" alt=\"Free Shipping & Return\" />\n                    </div>\n                    <div class=\"text\">\n                        <strong>\n                            Free Shipping & Return\n                        </strong>\n                        <p>\n                            Free shipping on all