INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (29,'Promotion Block One','et_promotion_one','<div class=\"promotion-one\">\n    <div class=\"page-main\">\n        <div class=\"item-row\">\n            <div class=\"item\">\n                <div class=\"item-inner\">\n                    <img src=\"{{media url=\'etrend/home/image1.jpg\'}}\" alt=\"image\" />\n                    <div class=\"text-content\">\n                        <p>\n                            Only <span>Three</span><br/>\n                            <strong>DAYS LEFT</strong><br/>\n                            on Fashion<br/>\n                            Weeks sale!\n                        </p>\n                        <a class=\"action primary\" href=\"#\">\n                            Shop Today\n                        </a>\n                    </div>\n                </div>\n            </div>\n            <div class=\"item\">\n                <div class=\"item-inner\">\n                    <img src=\"{{media url=\'etrend/home/image2.jpg\'}}\" alt=\"image\" />\n                    <div class=\"text-content\">\n                        <p>\n                            Get <span>Winter</span><br/>\n                            <strong>LOOKBOOK</strong><br/>\n                            with online<br/>\n                            purchase\n                        </p>\n                        <a class=\"action primary\" href=\"#\">\n                            Get Your Copy\n                        </a>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (30,'Promotion Block Two','et_promotion_two','<div class=\"promotion-two\" style=\"background-image: url({{media url=\'etrend/home/paralex-bg.jpg\'}});\">\n    <div class=\"page-main\">\n        <div class=\"content-main\">\n            <h3>\n                Summer Lookbook is out now!\n            </h3>\n            <a class=\"link-btn\" href=\"#\">\n                <span>Get your copy</span>\n            </a>\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (31,'Home Blogs','et_home_blogs','<div class=\"blogs-wrapper\">\n    <div class=\"page-main\">\n        <div class=\"section-title\">\n            <span>Latest <i>Blogs</i></span>\n        </div>\n        <div class=\"content-main\">\n            <div class=\"item-row\">\n                <div id=\"home-blogslider\" class=\"items owl-carousel owl-theme\">\n                    <div class=\"item\" style=\"display: none;\">\n                        <div class=\"item-inner\">\n                            <div class=\"img-block\">\n                                <a href=\"#\">\n                                    <img src=\"{{media url=\'etrend/blog/blog-1.png\'}}\" alt=\"\">\n                                </a>\n                                <div class=\"post-date\">\n                                    <span>July 30, 2020</span>\n                                </div>\n                            </div>\n                            <div class=\"info-block\">\n                                <div class=\"post-title\">\n                                    <a class=\"post-item-link\" href=\"#\">\n                                        Consectetur adipisci velit sed quia non numquam.\n                                    </a>\n                                </div>\n                                <div class=\"post-text\">\n                                    <p>\n                                        Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium.\n                                    </p>\n                                </div>\n                                <a class=\"action primary\" href=\"#\">\n                                    Read more\n                                </a>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"item\" style=\"display: none;\">\n                        <div class=\"item-inner\">\n                            <div class=\"img-block\">\n                                <a href=\"#\">\n                                    <img src=\"{{media url=\'etrend/blog/blog-2.png\'}}\" alt=\"#\">\n                                </a>\n                                <div class=\"post-date\">\n                                    <span>July 22, 2020</span>\n                                </div>\n                            </div>\n                            <div class=\"info-block\">\n                                <div class=\"post-title\">\n                                    <a class=\"post-item-link\" href=\"#\">\n                                        Ut labore et dolore magnam aliquam quaerat.\n                                    </a>\n                                </div>\n                                <div class=\"post-text\">\n                                    <p>\n                                        Lorem ipsum dolor sit amet, consectetur adipiscing elit sed do eiusmod tempor.\n                                    </p>\n                                </div>\n                                <a class=\"action primary\" href=\"#\">\n                                    Read more\n                                </a>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"item\" style=\"display: none;\">\n                        <div class=\"item-inner\">\n                            <div class=\"img-block\">\n                                <a href=\"#\">\n                                    <img src=\"{{media url=\'etrend/blog/blog-3.png\'}}\" alt=\"\">\n                                </a>\n                                <div class=\"post-date\">\n                                    <span>July 22, 2020</span>\n                                </div>\n                            </div>\n                            <div class=\"info-block\">\n                                <div class=\"post-title\">\n                                    <a class=\"post-item-link\" href=\"#\">\n                                        Neque porro quisquam est, qui dolorem ipsum quia.\n                                    </a>\n                                </div>\n                                <div class=\"post-text\">\n                                    <p>\n                                        Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore. \n                                    </p>\n                                </div>\n                                <a class=\"action primary\" href=\"#\">\n                                    Read more\n                                </a>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"item\" style=\"display: none;\">\n                        <div class=\"item-inner\">\n                            <div class=\"img-block\">\n                                <a href=\"#\">\n                                    <img src=\"{{media url=\'etrend/blog/blog-1.png\'}}\" alt=\"\">\n                                </a>\n                                <div class=\"post-date\">\n                                    <span>July 14, 2020</span>\n                                </div>\n                            </div>\n                            <div class=\"info-block\">\n                                <div class=\"post-title\">\n                                    <a class=\"post-item-link\" href=\"#\">\n                                        Ut labore et dolore magnam aliquam quaerat voluptatem.\n                                    </a>\n                                </div>\n                                <div class=\"post-text\">\n                                    <p>\n                                        Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur.\n                                    </p>\n                                </div>\n                                <a class=\"action primary\" href=\"#\">\n                                    Read more\n                                </a>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (32,'Home Brand Slider','et_brand_slider','<div class=\"brands-wrapper\">\n    <div class=\"page-main\">\n        <div class=\"section-title\">\n            <span>Shop By <i>Brand</i></span>\n        </div>\n        <div class=\"content-main\">\n            <div class=\"brands-slider owl-carousel owl-theme\">\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand1.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand2.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand3.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand4.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand5.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand1.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n                <div class=\"item\">\n                    <a href=\"#\">\n                        <img src=\"{{media url=\'etrend/brand/brand2.png\'}}\" alt=\"brand-image\" />\n                    </a>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (33,'Footer Logo and Socials Content','et_footer_logo_socials','<div class=\"logo-socials align-center\">\n<img src=\"{{media url=\'etrend/footer/logo.png\'}}\" title=\"Etrend\" alt=\"Etrend\" />\n<p>\n    Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, \n    eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo.\n</p>\n{{widget type=\"Magento\\Cms\\Block\\Widget\\Block\" template=\"widget/static_block/default.phtml\" block_id=\"social_icons\"}}\n</div>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (34,'Social Icons','et_social_icons','<ul class=\"socials\">\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-facebook\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-twitter\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-pinterest-p\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-youtube-play\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-vimeo\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                        <li>\n                            <a href=\"#\">\n                                <i class=\"fa fa-instagram\" aria-hidden=\"true\"></i>\n                            </a>\n                        </li>\n                    </ul>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (35,'Custom Tab 1','et_custom_tab1','<p><strong>Custom Tab Content</strong></p>\n<p>At vero eos et accusamus et iusto odio dignissimos ducimus qui blanditiis praesentium voluptatum deleniti atque corrupti quos dolores et quas molestias excepturi sint occaecati cupiditate non provident,</p>\n<ul>\n<li>Similique sunt in culpa qui officia deserunt mollitia animi.</li>\n<li>Nam libero tempore cum soluta nobis est.</li>\n<li>Itaque earum rerum hic tenetur a sapiente delectus ut aut reiciendis.</li>\n</ul>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
INSERT INTO `cms_block` (`block_id`, `title`, `identifier`, `content`, `creation_time`, `update_time`, `is_active`) VALUES (36,'Custom Tab 2','et_custom_tab2','<p><strong>Custom Tab Content</strong></p>\n<p>Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo.</p>\n<p>Nemo enim ipsam voluptatem quia voluptas sit aspernatur aut odit aut fugit, sed quia consequuntur magni dolores eos qui ratione voluptatem sequi nesciunt.</p>\n<p><img src=\"{{media url=\'etrend/tab-img.png\'}}\" alt=\"\" /> </p>','2026-04-07 17:12:12','2026-04-07 17:12:12',1);
